export interface Hazard {
  id: string;
  type: string;
  description: string;
  severity: 'Low' | 'Medium' | 'High' | 'Critical';
  dateReported: number; // timestamp
  status: 'Reported' | 'Landlord Notified' | 'Action Required' | 'Resolved';
  imageUrl?: string;
}

export interface ScanResult {
  isSafe: boolean;
  score: number; // 0-100
  issues: string[];
  summary: string;
}

export interface UserLocation {
  latitude: number;
  longitude: number;
  borough?: string;
}

export enum AppTab {
  HOME = 'home',
  SCAN = 'scan',
  TRACKER = 'tracker',
  PROTECT = 'protect'
}

export enum Tone {
  DIPLOMATIC = 'Diplomatic',
  FIRM = 'Firm',
  STRICTLY_LEGAL = 'Strictly Legal'
}

import { GoogleGenAI, Type } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const analyzeContract = async (imageBase64: string): Promise<{ isSafe: boolean; summary: string; issues: string[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Using image model for document scanning
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: imageBase64
            }
          },
          {
            text: `You are an expert UK housing lawyer in 2026. The Renters' Rights Act 2026 is in effect.
            Analyze this tenancy agreement image.
            Look specifically for:
            1. Section 21 clauses (Illegal).
            2. Fixed terms longer than allowed or preventing the rolling monthly standard (Illegal).
            3. Excessive rent review clauses.
            4. Illegal fees.

            Return a JSON object with:
            - isSafe: boolean
            - summary: string (short analysis)
            - issues: string[] (list of specific illegal clauses found)`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isSafe: { type: Type.BOOLEAN },
            summary: { type: Type.STRING },
            issues: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Contract analysis failed:", error);
    return {
      isSafe: false,
      summary: "Could not analyze document. Please ensure the image is clear.",
      issues: ["Analysis failed"]
    };
  }
};

export const analyzeHazard = async (imageBase64: string): Promise<{ type: string; severity: 'Low' | 'Medium' | 'High' | 'Critical'; description: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: imageBase64
            }
          },
          {
            text: `Analyze this image of a potential housing hazard in the UK.
            Under Awaab's Law (2026), categorize this hazard.
            Return JSON with:
            - type: string (e.g., "Black Mould", "Structural Leak", "Broken Boiler")
            - severity: "Low" | "Medium" | "High" | "Critical"
            - description: string (brief assessment of the risk to health)`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING },
            severity: { type: Type.STRING, enum: ['Low', 'Medium', 'High', 'Critical'] },
            description: { type: Type.STRING }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Hazard analysis failed:", error);
    return {
      type: "Unknown",
      severity: "Medium",
      description: "AI could not identify the hazard clearly."
    };
  }
};

export const detectBiddingWar = async (imageBase64: string): Promise<{ isIllegal: boolean; evidence: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: imageBase64
            }
          },
          {
            text: `Analyze this screenshot (WhatsApp, Email, or SMS).
            Does this show a landlord or agent encouraging a "Bidding War" (asking for more rent than advertised) or pitting tenants against each other?
            This is illegal under the 2026 Renters' Rights Act.
            Return JSON:
            - isIllegal: boolean
            - evidence: string (quote the specific text that proves the violation)`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
            isIllegal: { type: Type.BOOLEAN },
            evidence: { type: Type.STRING }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Bidding analysis failed:", error);
    return {
      isIllegal: false,
      evidence: "Could not analyze screenshot."
    };
  }
};

export const generateResponse = async (tone: string, context: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Draft an email response to a landlord in a ${tone} tone.
      Context: ${context}.
      Cite the UK Renters' Rights Act 2026 or Awaab's Law where appropriate.
      Keep it concise and professional.`,
    });
    return response.text || "Could not generate response.";
  } catch (error) {
    console.error("Response generation failed:", error);
    return "Error generating response. Please try again.";
  }
};

import React from 'react';
import { motion } from 'framer-motion';
import { Loader2 } from 'lucide-react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const NeuButton: React.FC<ButtonProps> = ({ children, variant = 'primary', isLoading, className, ...props }) => {
  const baseStyle = "relative inline-flex items-center justify-center px-6 py-3 font-display font-bold text-lg transition-all border-2 border-black active:translate-x-[2px] active:translate-y-[2px] active:shadow-none disabled:opacity-50 disabled:pointer-events-none";

  const variants = {
    primary: "bg-neone-blue text-black shadow-neu hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,1)]",
    secondary: "bg-white text-black shadow-neu hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,1)]",
    danger: "bg-neone-red text-white shadow-neu hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,1)]",
    ghost: "border-none shadow-none text-gray-600 hover:bg-gray-100"
  };

  return (
    <motion.button 
      whileTap={{ scale: 0.98 }}
      className={`${baseStyle} ${variants[variant]} ${className || ''}`}
      {...props}
    >
      {isLoading && <Loader2 className="mr-2 h-5 w-5 animate-spin" />}
      {children}
    </motion.button>
  );
};

export const SoftCard: React.FC<{ children: React.ReactNode; className?: string }> = ({ children, className }) => (
  <motion.div 
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0 }}
    className={`bg-white/90 backdrop-blur-sm rounded-2xl p-6 shadow-sm border border-gray-100 ${className || ''}`}
  >
    {children}
  </motion.div>
);

export const NeuAlert: React.FC<{ type: 'danger' | 'info' | 'success'; title: string; children: React.ReactNode }> = ({ type, title, children }) => {
  const colors = {
    danger: 'bg-neone-red text-white',
    info: 'bg-neone-blue text-black',
    success: 'bg-neone-green text-black',
  };

  return (
    <div className={`${colors[type]} border-2 border-black p-4 shadow-neu mb-4`}>
      <h4 className="font-display font-bold text-lg mb-1 flex items-center gap-2">
        {type === 'danger' && '⚠️'} 
        {type === 'success' && '🛡️'}
        {type === 'info' && 'ℹ️'}
        {title}
      </h4>
      <p className="font-sans text-sm opacity-90 leading-relaxed">{children}</p>
    </div>
  );
};

export const TabBar: React.FC<{ activeTab: string; onTabChange: (tab: any) => void }> = ({ activeTab, onTabChange }) => {
  // Imported locally to avoid circular deps if placed elsewhere, or just pass icon components
  // For simplicity, we assume parent handles logic, but here's the visual container
  return (
    <div className="fixed bottom-0 left-0 w-full bg-white border-t-2 border-black pb-safe pt-2 px-6 flex justify-between items-center z-50 h-20 shadow-[0_-4px_0_0_rgba(0,0,0,0.05)]">
       {/* Content injected by parent */}
    </div>
  );
}

