const ScannerView = () => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<ScanResult | any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);

    // Convert to base64
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];

      let res;
      if (mode === 'contract') {
        res = await analyzeContract(base64);
      } else if (mode === 'bidding') {
        res = await detectBiddingWar(base64);
      } else {
        // Mock EPC for now
        await new Promise(r => setTimeout(r, 2000));
        res = { score: 'C', valid: true, summary: "Meets 2026 Efficiency Standards." };
      }

      setResult(res);
      setScanning(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <h2 className="font-display text-3xl font-bold">Compliance Pulse</h2>

      <div className="flex gap-2 p-1 bg-gray-200 rounded-lg">
        {['contract', 'bidding', 'epc'].map((m) => (
          <button
            key={m}
            onClick={() => { setMode(m as any); setResult(null); }}
            className={`flex-1 py-2 text-sm font-bold rounded-md capitalize transition-all ${mode === m ? 'bg-white shadow-sm text-black' : 'text-gray-500'}`}
          >
            {m}
          </button>
        ))}
      </div>

      <div className="relative h-64 bg-neone-dark rounded-xl border-2 border-black overflow-hidden flex flex-col items-center justify-center text-white">
        {scanning && (
          <motion.div 
            className="absolute top-0 left-0 w-full h-1 bg-neone-green shadow-[0_0_15px_rgba(6,214,160,0.8)] z-10"
            animate={{ top: ['0%', '100%', '0%'] }}
            transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
          />
        )}

        {!result && !scanning && (
          <div className="text-center p-6">
            <Camera className="w-12 h-12 mx-auto mb-4 text-gray-400" />
            <p className="mb-4 text-gray-300">Upload a photo of your {mode}</p>
            <NeuButton onClick={() => fileInputRef.current?.click()} variant="secondary">
              <Upload className="w-4 h-4 mr-2" /> Select Image
            </NeuButton>
            <input 
              ref={fileInputRef} 
              type="file" 
              accept="image/*" 
              className="hidden" 
              onChange={handleFileUpload} 
            />
          </div>
        )}

        {scanning && (
          <div className="flex flex-col items-center">
            <Scan className="w-12 h-12 text-neone-green animate-pulse mb-4" />
            <p className="font-mono text-neone-green">AI ANALYZING...</p>
          </div>
        )}

        {result && !scanning && (
          <div className="absolute inset-0 bg-white text-black p-6 overflow-y-auto">
            {mode === 'contract' && (
              <>
                <div className={`text-4xl font-display font-bold mb-4 ${result.isSafe ? 'text-neone-green' : 'text-neone-red'}`}>
                  {result.isSafe ? 'LEGALLY SOUND' : 'RISK DETECTED'}
                </div>
                <p className="mb-4 text-sm">{result.summary}</p>
                {result.issues.length > 0 && (
                   <ul className="list-disc pl-5 text-sm space-y-1 bg-red-50 p-3 rounded border border-red-200">
                     {result.issues.map((issue: string, i: number) => (
                       <li key={i} className="text-red-700 font-medium">{issue}</li>
                     ))}
                   </ul>
                )}
              </>
            )}
            {mode === 'bidding' && (
               <>
                <div className={`text-3xl font-display font-bold mb-4 ${result.isIllegal ? 'text-neone-red' : 'text-neone-green'}`}>
                  {result.isIllegal ? 'ILLEGAL BIDDING' : 'NO VIOLATION'}
                </div>
                <p className="text-sm bg-gray-100 p-3 rounded">{result.evidence}</p>
                {result.isIllegal && (
                  <div className="mt-4">
                     <p className="text-xs font-bold mb-2">ACTION:</p>
                     <NeuButton variant="danger" className="w-full text-sm py-2">Report to Council</NeuButton>
                  </div>
                )}
               </>
            )}
             <button onClick={() => setResult(null)} className="absolute top-4 right-4 text-gray-400 hover:text-black">
               <XCircle />
             </button>
          </div>
        )}
      </div>

      <NeuAlert type="info" title="Privacy First">
        Images are processed securely by Gemini AI and are not stored permanently on our servers.
      </NeuAlert>
    </div>
  );
};

const TrackerView = () => {
  const [hazards, setHazards] = useState<Hazard[]>([
    {
      id: '1',
      type: 'Black Mould',
      description: 'Found in bedroom corner, approx 1m wide.',
      severity: 'High',
      dateReported: Date.now() - 1000 * 60 * 60 * 24 * 13, // 13 days ago
      status: 'Landlord Notified'
    }
  ]);
  const [isAdding, setIsAdding] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAddHazard = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Simulate analysis
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const analysis = await analyzeHazard(base64);

      const newHazard: Hazard = {
        id: Math.random().toString(36).substr(2, 9),
        type: analysis.type,
        description: analysis.description,
        severity: analysis.severity,
        dateReported: Date.now(),
        status: 'Reported',
        imageUrl: URL.createObjectURL(file)
      };
      setHazards([newHazard, ...hazards]);
      setIsAdding(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-end">
        <h2 className="font-display text-3xl font-bold">Awaab's Law<br/>Tracker</h2>
        <NeuButton onClick={() => fileInputRef.current?.click()} className="h-10 px-4 text-sm">
          + Log New
        </NeuButton>
        <input ref={fileInputRef} type="file" className="hidden" onChange={handleAddHazard} />
      </div>

      <div className="space-y-4">
        {hazards.map(h => {
          const daysElapsed = differenceInDays(Date.now(), h.dateReported);
          const daysLeft = 14 - daysElapsed;
          const isUrgent = daysLeft <= 1;

          return (
            <SoftCard key={h.id} className="relative overflow-hidden border-2 border-transparent hover:border-black transition-all">
              <div className="flex justify-between items-start mb-3">
                <div>
                  <span className={`inline-block px-2 py-1 text-xs font-bold uppercase rounded mb-2 ${
                    h.severity === 'Critical' || h.severity === 'High' ? 'bg-red-100 text-red-800' : 'bg-yellow-100 text-yellow-800'
                  }`}>
                    {h.severity} Priority
                  </span>
                  <h3 className="font-bold text-lg">{h.type}</h3>
                </div>
                <div className="text-right">
                  <div className={`font-mono text-2xl font-bold ${isUrgent ? 'text-neone-red' : 'text-neone-blue'}`}>
                    {daysLeft > 0 ? daysLeft : 0}
                  </div>
                  <div className="text-xs uppercase font-bold text-gray-400">Days Left</div>
                </div>
              </div>

              <p className="text-sm text-gray-600 mb-4">{h.description}</p>

              <div className="flex gap-2">
                 {daysLeft <= 0 ? (
                   <NeuButton variant="danger" className="w-full text-sm py-2 animate-pulse">
                     <Siren className="w-4 h-4 mr-2" /> GENERATE OMBUDSMAN REPORT
                   </NeuButton>
                 ) : (
                   <div className="w-full bg-gray-100 rounded h-10 flex items-center justify-center text-xs font-bold text-gray-400 border border-gray-200">
                     <Clock className="w-3 h-3 mr-2" /> Action unlocks in {daysLeft} days
                   </div>
                 )}
              </div>
            </SoftCard>
          );
        })}
      </div>
    </div>
  );
};

const ProtectView = () => {
  const [context, setContext] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGenerate = async (tone: Tone) => {
    if (!context) return;
    setLoading(true);
    const res = await generateResponse(tone, context);
    setResponse(res);
    setLoading(false);
  };

  return (
    <div className="space-y-6 pb-24">
       <h2 className="font-display text-3xl font-bold">Smart Response</h2>

       <SoftCard>
         <label className="block text-sm font-bold mb-2">What's the situation?</label>
         <textarea 
          className="w-full p-3 border-2 border-gray-200 rounded-lg focus:border-black focus:outline-none transition-colors min-h-[100px]"
          placeholder="e.g. My landlord is trying to increase rent by 20% without proper notice..."
          value={context}
          onChange={(e) => setContext(e.target.value)}
         />

         <div className="grid grid-cols-1 gap-2 mt-4">
           {Object.values(Tone).map(t => (
             <NeuButton 
                key={t} 
                variant="secondary" 
                onClick={() => handleGenerate(t)}
                disabled={!context || loading}
                className="text-sm py-2"
              >
               Generate {t} Response
             </NeuButton>
           ))}
         </div>
       </SoftCard>

       {loading && (
         <div className="flex justify-center p-8">
           <Loader2 className="animate-spin w-8 h-8 text-neone-blue" />
         </div>
       )}

       {response && (
         <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
            <div className="bg-white border-2 border-black shadow-neu p-4 relative">
              <h3 className="font-bold mb-2 flex items-center gap-2">
                <Send className="w-4 h-4" /> Draft Response
              </h3>
              <div className="whitespace-pre-wrap text-sm font-sans text-gray-700 leading-relaxed">
                {response}
              </div>
              <NeuButton 
                variant="primary" 
                className="mt-4 w-full text-sm"
                onClick={() => {navigator.clipboard.writeText(response); alert('Copied!')}}
              >
                Copy to Clipboard
              </NeuButton>
            </div>
         </motion.div>
       )}
    </div>
  );
};

