const ScannerView = () => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<ScanResult | any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;

    const messages = {
      contract: [
        "Scanning document structure...",
        "Reading clauses...",
        "Checking Renters' Rights Act 2026...",
        "Detecting illegal Section 21 terms...",
        "Verifying notice periods...",
        "Finalizing legal assessment..."
      ],
      bidding: [
        "Analyzing communication...",
        "Detecting bidding patterns...",
        "Checking 2026 Bidding Laws...",
        "Identifying harassment...",
        "Compiling evidence..."
      ],
      epc: [
        "Identifying heating elements...",
        "Analyzing thermal efficiency...",
        "Checking 2026 Energy Mandates...",
        "Calculating comfort score..."
      ]
    };

    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;

    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1200);

    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];

      let res;
      try {
        if (mode === 'contract') {
          res = await analyzeContract(base64);
        } else if (mode === 'bidding') {
          res = await detectBiddingWar(base64);
