        console.error("Scan error:", e);
        res = { isSafe: false, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
