import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeContract = async (imageBase64: string): Promise<{ isSafe: boolean; summary: string; issues: string[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Using pro model for complex contract analysis
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: imageBase64
            }
          },
          {
            text: `You are an expert UK housing lawyer in 2026. The Renters' Rights Act 2026 is in effect.
            Analyze this tenancy agreement image.
            Look specifically for:
            1. Section 21 clauses (Illegal).
            2. Fixed terms longer than allowed or preventing the rolling monthly standard (Illegal).
            3. Excessive rent review clauses.
            4. Illegal fees.

            Return a JSON object with:
            - isSafe: boolean
            - summary: string (short analysis)
            - issues: string[] (list of specific illegal clauses found)`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isSafe: { type: Type.BOOLEAN },
            summary: { type: Type.STRING },
            issues: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Contract analysis failed:", error);
    return {
      isSafe: false,
      summary: "Could not analyze document. Please ensure the image is clear.",
      issues: ["Analysis failed"]
    };
  }
};

