const ScannerView = () => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;

    const messages = {
      contract: [
        "Analyzing contract clauses...",
        "Checking against Renters' Rights Act 2026...",
        "Detecting prohibited fees...",
        "Verifying tenure security...",
        "Validating notice periods...",
        "Finalizing legal assessment..."
      ],
      bidding: [
        "Analyzing communication pattern...",
        "Detecting illegal bidding requests...",
        "Checking Renters' Rights Act 2026...",
        "Identifying harassment markers...",
        "Compiling evidence..."
      ],
      epc: [
        "Scanning thermal properties...",
        "Identifying glazing and insulation...",
        "Checking 2026 Energy Efficiency Mandates...",
        "Calculating comfort score...",
        "Generating recommendations..."
      ]
    };

    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;

    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1500);

    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];

      let res;
      try {
        if (mode === 'contract') {
          res = await analyzeContract(base64);
        } else if (mode === 'bidding') {
          res = await detectBiddingWar(base64);
        } else {
          res = await analyzeEPC(base64);
        }
      } catch (e) {
        console.error("Scan error:", e);
        res = { isSafe: false, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <h2 className="font-display text-3xl font-bold">Compliance Pulse</h2>

      <div className="flex gap-2 p-1 bg-gray-200 rounded-lg">
        {['contract', 'bidding', 'epc'].map((m) => (
          <button
            key={m}
            onClick={() => { setMode(m as any); setResult(null); }}
            className={`flex-1 py-2 text-sm font-bold rounded-md capitalize transition-all ${mode === m ? 'bg-white shadow-sm text-black' : 'text-gray-500'}`}
          >
            {m === 'epc' ? 'EPC Shield' : m}
          </button>
        ))}
      </div>

