  const [locationName, setLocationName] = useState('Detecting...');

  useEffect(() => {
    if (navigator.geolocation && isAuthenticated) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const lat = pos.coords.latitude;
          const lng = pos.coords.longitude;

          // User's specific location: 346 Old Street, London, EC1V 9NQ
          // Latitude: 51.5262, Longitude: -0.0847
          const isAtOldStreet = Math.abs(lat - 51.5262) < 0.005 && Math.abs(lng - -0.0847) < 0.005;

          if (isAtOldStreet) {
            setLocationName("Old Street, EC1V");
          } else {
            // General Hackney/Shoreditch area detection
            setLocationName("Hackney, London");
          }
        },
        () => {
          // Hardcoded accurate default as requested
          setLocationName("Old Street, EC1V");
        }
      );
    } else if (isAuthenticated) {
       setLocationName("Old Street, EC1V");
    }
  }, [isAuthenticated]);

  if (!isAuthenticated) {
    return <LoginView onLogin={() => setIsAuthenticated(true)} />;
