                        {result.comfort}/100
                      </div>
                    </div>
                    <div className="text-right">
                       <h3 className="text-sm font-bold text-gray-500">EST. RATING</h3>
                       <div className={`text-4xl font-display font-bold ${result.compliance ? 'text-neone-green' : 'text-neone-red'}`}>
                        {result.score}
                       </div>
                    </div>
                 </div>

                <div className={`p-3 rounded mb-4 text-sm font-bold ${result.compliance ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                   {result.compliance ? '✅ COMPLIANT WITH 2026 STANDARDS' : '⚠️ NON-COMPLIANT (BELOW C)'}
