export const NeuButton: React.FC<ButtonProps> = ({ children, variant = 'primary', isLoading, className, ...props }) => {
  const baseStyle = "relative inline-flex items-center justify-center px-6 py-3 font-display font-bold text-lg transition-all border-2 border-black dark:border-white active:translate-x-[2px] active:translate-y-[2px] active:shadow-none disabled:opacity-50 disabled:pointer-events-none rounded-lg";

  const variants = {
    primary: "bg-neone-blue text-black shadow-neu dark:shadow-neu-white hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] dark:hover:shadow-[6px_6px_0px_0px_rgba(255,255,255,1)]",
