const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [view, setView] = useState<'scan' | 'history'>('scan');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const [feedbackGiven, setFeedbackGiven] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;
    const messages = {
      contract: ["Analyzing clauses...", "Checking 2026 Act...", "Validating..."],
      bidding: ["Checking patterns...", "Detecting illegality...", "Compiling..."],
      epc: ["Scanning thermal...", "Checking mandates...", "Calculating..."]
    };
    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;
    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1500);
    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);
    setFeedbackGiven(false);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      try {
        if (mode === 'contract') res = await analyzeContract(base64);
        else if (mode === 'bidding') res = await detectBiddingWar(base64);
        else res = await analyzeEPC(base64);
      } catch (e) {
        res = { isSafe: false, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);

      // Save to history
      const historyItem: ScanHistoryItem = {
        id: Date.now().toString(),
        date: Date.now(),
        type: mode,
        summary: res.summary || res.evidence || "Scan completed",
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk'
      };
      onSaveHistory(historyItem);
    };
    reader.readAsDataURL(file);
  };

  const submitFeedback = () => {
    setFeedbackGiven(true);
    // Mock logging feedback
    setTimeout(() => alert("Thanks! Your feedback helps train our Legal Guardian AI."), 300);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h2 className="font-display text-3xl font-bold">Compliance Pulse</h2>
        <button onClick={() => setView(view === 'scan' ? 'history' : 'scan')} className="p-2 bg-gray-200 dark:bg-gray-700 rounded-full">
           {view === 'scan' ? <History className="w-5 h-5" /> : <Scan className="w-5 h-5" />}
        </button>
      </div>

      {view === 'history' ? (
        <div className="space-y-4">
           {history.length === 0 && <p className="text-gray-500 text-center py-10">No scan history yet.</p>}
           {history.map(item => (
             <SoftCard key={item.id} className="border-l-4 border-l-gray-300 dark:border-l-gray-500">
                <div className="flex justify-between items-start">
                  <div>
                    <span className="text-xs uppercase font-bold text-gray-400">{item.type}</span>
                    <h4 className="font-bold">{format(item.date, 'dd MMM yyyy, HH:mm')}</h4>
                  </div>
                  <span className={`px-2 py-0.5 rounded text-xs font-bold ${item.status === 'safe' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                    {item.status.toUpperCase()}
                  </span>
                </div>
                <p className="text-sm mt-2 text-gray-600 dark:text-gray-300">{item.summary}</p>
             </SoftCard>
           ))}
        </div>
      ) : (
        <>
          <div className="flex gap-2 p-1 bg-gray-200 dark:bg-gray-700 rounded-lg">
            {['contract', 'bidding', 'epc'].map((m) => (
              <button
                key={m}
                onClick={() => { setMode(m as any); setResult(null); }}
                className={`flex-1 py-2 text-sm font-bold rounded-md capitalize transition-all ${mode === m ? 'bg-white dark:bg-gray-800 shadow-sm text-black dark:text-white' : 'text-gray-500 dark:text-gray-400'}`}
              >
                {m === 'epc' ? 'EPC Shield' : m}
              </button>
            ))}
          </div>

          <div className="relative h-fit min-h-[16rem] bg-neone-dark rounded-xl border-2 border-black dark:border-white overflow-hidden flex flex-col items-center justify-center text-white">
            {scanning && (
              <motion.div 
                className="absolute top-0 left-0 w-full h-1 bg-neone-green shadow-[0_0_15px_rgba(6,214,160,0.8)] z-10"
                animate={{ top: ['0%', '100%', '0%'] }}
                transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
              />
            )}

            {!result && !scanning && (
              <div className="text-center p-6 w-full h-64 flex flex-col items-center justify-center">
                <Camera className="w-12 h-12 mx-auto mb-4 text-gray-400" />
                <p className="mb-4 text-gray-300">
                  {mode === 'epc' ? 'Scan radiator, window or room' : `Upload a photo of your ${mode}`}
                </p>
                <NeuButton onClick={() => fileInputRef.current?.click()} variant="secondary" className="w-full">
                  <Upload className="w-4 h-4 mr-2" /> Select Image
                </NeuButton>
                <input 
                  ref={fileInputRef} 
                  type="file" 
                  accept="image/*" 
                  className="hidden" 
                  onChange={handleFileUpload} 
                />
              </div>
            )}

            {scanning && (
              <div className="flex flex-col items-center justify-center h-64 px-8 text-center w-full">
                <Scan className="w-12 h-12 text-neone-green animate-pulse mb-4" />
                 <AnimatePresence mode="wait">
                    <motion.div
                        key={loadingMessage}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ duration: 0.2 }}
                        className="w-full"
                    >
                       <p className="font-mono text-neone-green font-bold text-sm leading-tight">
                        {loadingMessage.toUpperCase()}
                       </p>
                    </motion.div>
                 </AnimatePresence>
              </div>
            )}

            {result && !scanning && (
              <div className="w-full bg-white dark:bg-gray-800 text-black dark:text-white p-6">
                <div className="flex justify-between items-start">
                   <div>
                     {mode === 'contract' && (
                       <h3 className={`text-2xl font-display font-bold mb-2 ${result.isSafe ? 'text-neone-green' : 'text-neone-red'}`}>
                         {result.isSafe ? 'LEGALLY SOUND' : 'RISK DETECTED'}
                       </h3>
                     )}
                     {mode === 'bidding' && (
                        <h3 className={`text-2xl font-display font-bold mb-2 ${result.isIllegal ? 'text-neone-red' : 'text-neone-green'}`}>
                          {result.isIllegal ? 'ILLEGAL BIDDING' : 'NO VIOLATION'}
                        </h3>
                     )}
                     {mode === 'epc' && (
                        <h3 className={`text-2xl font-display font-bold mb-2 ${result.compliance ? 'text-neone-green' : 'text-neone-red'}`}>
                          RATING: {result.score}
                        </h3>
                     )}
                   </div>
                   <button onClick={() => setResult(null)} className="text-gray-400 hover:text-black dark:hover:text-white">
                     <XCircle />
                   </button>
                </div>

                <p className="mb-4 text-sm text-gray-700 dark:text-gray-300">{result.summary || result.evidence}</p>

                {/* Feedback Section */}
                {!feedbackGiven ? (
                  <div className="mt-6 pt-4 border-t border-gray-100 dark:border-gray-700">
                    <p className="text-xs font-bold text-gray-500 mb-2">WAS THIS SCAN ACCURATE?</p>
                    <div className="flex gap-2">
                       <button onClick={submitFeedback} className="flex-1 bg-gray-100 dark:bg-gray-700 hover:bg-green-100 dark:hover:bg-green-900/30 p-2 rounded flex justify-center items-center gap-2 transition-colors">
                          <ThumbsUp className="w-4 h-4 text-green-600" /> <span className="text-xs font-bold">Yes</span>
                       </button>
                       <button onClick={submitFeedback} className="flex-1 bg-gray-100 dark:bg-gray-700 hover:bg-red-100 dark:hover:bg-red-900/30 p-2 rounded flex justify-center items-center gap-2 transition-colors">
                          <AlertTriangle className="w-4 h-4 text-red-600" /> <span className="text-xs font-bold">No</span>
                       </button>
                    </div>
                  </div>
                ) : (
                  <div className="mt-6 pt-4 border-t border-gray-100 dark:border-gray-700 text-center">
                    <p className="text-xs font-bold text-neone-green">FEEDBACK SUBMITTED</p>
                  </div>
                )}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

const TrackerView = () => {
  const [hazards, setHazards] = useState<Hazard[]>([
    {
      id: '1',
      type: 'Black Mould',
      description: 'Found in bedroom corner, approx 1m wide.',
      severity: 'High',
      dateReported: Date.now() - 1000 * 60 * 60 * 24 * 13, // 13 days ago
      status: 'Landlord Notified'
    }
  ]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const enableNotifications = async () => {
    if ("Notification" in window) {
      const permission = await Notification.requestPermission();
      if (permission === "granted") {
        new Notification("RentShield Alerts Enabled", { body: "We will notify you when action timers expire." });
      } else {
        alert("Permission denied. You can enable this in your browser settings.");
      }
    } else {
       alert("Your browser does not support notifications.");
    }
  };

  const handleAddHazard = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const analysis = await analyzeHazard(base64);

      const newHazard: Hazard = {
        id: Math.random().toString(36).substr(2, 9),
        type: analysis.type,
        description: analysis.description,
        severity: analysis.severity,
        dateReported: Date.now(),
        status: 'Reported',
        imageUrl: URL.createObjectURL(file)
      };
      setHazards([newHazard, ...hazards]);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-end">
        <h2 className="font-display text-3xl font-bold">Awaab's Law<br/>Tracker</h2>
        <div className="flex gap-2">
          <button onClick={enableNotifications} className="w-10 h-10 rounded-full bg-gray-200 dark:bg-gray-700 flex items-center justify-center">
             <Bell className="w-5 h-5" />
          </button>
          <NeuButton onClick={() => fileInputRef.current?.click()} className="h-10 px-4 text-sm">
            + Log
          </NeuButton>
        </div>
        <input ref={fileInputRef} type="file" className="hidden" onChange={handleAddHazard} />
      </div>

      <div className="space-y-4">
        {hazards.map(h => {
          const daysElapsed = differenceInDays(Date.now(), h.dateReported);
          const daysLeft = 14 - daysElapsed;
          const isUrgent = daysLeft <= 1;

          return (
            <SoftCard key={h.id} className="relative overflow-hidden border-2 border-transparent hover:border-black dark:hover:border-white transition-all">
              <div className="flex justify-between items-start mb-3">
                <div>
                  <span className={`inline-block px-2 py-1 text-xs font-bold uppercase rounded mb-2 ${
                    h.severity === 'Critical' || h.severity === 'High' ? 'bg-red-100 text-red-800' : 'bg-yellow-100 text-yellow-800'
                  }`}>
                    {h.severity} Priority
                  </span>
                  <h3 className="font-bold text-lg">{h.type}</h3>
                </div>
                <div className="text-right">
                  <div className={`font-mono text-2xl font-bold ${isUrgent ? 'text-neone-red' : 'text-neone-blue'}`}>
                    {daysLeft > 0 ? daysLeft : 0}
                  </div>
                  <div className="text-xs uppercase font-bold text-gray-400">Days Left</div>
                </div>
              </div>

              <p className="text-sm text-gray-600 dark:text-gray-300 mb-4">{h.description}</p>

              <div className="flex gap-2">
                 {daysLeft <= 0 ? (
                   <NeuButton variant="danger" className="w-full text-sm py-2 animate-pulse">
                     <Siren className="w-4 h-4 mr-2" /> GENERATE OMBUDSMAN REPORT
                   </NeuButton>
                 ) : (
                   <div className="w-full bg-gray-100 dark:bg-gray-700 rounded h-10 flex items-center justify-center text-xs font-bold text-gray-400 dark:text-gray-500 border border-gray-200 dark:border-gray-600">
                     <Clock className="w-3 h-3 mr-2" /> Action unlocks in {daysLeft} days
                   </div>
                 )}
              </div>
            </SoftCard>
          );
        })}
      </div>
    </div>
  );
};

