            + Log
          </NeuButton>
        </div>
        <input ref={fileInputRef} type="file" className="hidden" onChange={handleAddHazard} />
      </div>

      <div className="space-y-4">
        {hazards.map(h => {
          const daysElapsed = differenceInDays(Date.now(), h.dateReported);
          const daysLeft = 14 - daysElapsed;
          const progress = Math.min((daysElapsed / 14) * 100, 100);

          return (
            <SoftCard key={h.id} className="relative overflow-hidden border-2 border-transparent hover:border-black dark:hover:border-white transition-all">
              <div className="flex justify-between items-start mb-3">
                <div>
                  <span className={`inline-block px-2 py-1 text-xs font-bold uppercase rounded mb-2 ${
                    h.severity === 'Critical' || h.severity === 'High' ? 'bg-red-100 text-red-800' : 'bg-yellow-100 text-yellow-800'
                  }`}>
                    {h.severity} Priority
                  </span>
                  <h3 className="font-bold text-lg">{h.type}</h3>
                </div>
                <div className="text-right">
                   <div className="text-xs uppercase font-bold text-gray-400 mb-1">Legal Timeline</div>
                   <div className="flex items-center gap-1 text-xs font-bold">
                      <span className="text-gray-500">Day {daysElapsed}</span>
                      <span className="text-gray-300">/</span>
                      <span className="text-neone-red">14</span>
                   </div>
                </div>
              </div>

              {/* Visual Timeline Bar */}
              <div className="w-full h-3 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden mb-4 relative">
                 <motion.div 
                   className={`h-full ${daysLeft <= 2 ? 'bg-neone-red' : 'bg-neone-blue'}`} 
                   initial={{ width: 0 }} 
                   animate={{ width: `${progress}%` }} 
                 />
              </div>

              <div className="flex justify-between text-xs text-gray-500 mb-4 px-1">
                 <div>Reported<br/>{format(h.dateReported, 'dd MMM')}</div>
                 <div className="text-right">Deadline<br/>{format(addDays(h.dateReported, 14), 'dd MMM')}</div>
              </div>

              <p className="text-sm text-gray-600 dark:text-gray-300 mb-4 bg-gray-50 dark:bg-gray-900 p-2 rounded">{h.description}</p>

              <div className="flex gap-2">
                 {daysLeft <= 0 ? (
                   <NeuButton variant="danger" className="w-full text-sm py-2 animate-pulse">
                     <Siren className="w-4 h-4 mr-2" /> GENERATE OMBUDSMAN REPORT
                   </NeuButton>
                 ) : (
                   <div className="w-full bg-gray-100 dark:bg-gray-700 rounded h-10 flex items-center justify-center text-xs font-bold text-gray-400 dark:text-gray-500 border border-gray-200 dark:border-gray-600">
                     <Clock className="w-3 h-3 mr-2" /> Action unlocks in {daysLeft} days
                   </div>
                 )}
              </div>
            </SoftCard>
          );
        })}
      </div>
    </div>
  );
};

