const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [view, setView] = useState<'scan' | 'history'>('scan');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const [feedbackGiven, setFeedbackGiven] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;
    const messages = {
      contract: ["Analyzing clauses...", "Checking 2026 Act...", "Validating..."],
      bidding: ["Checking patterns...", "Detecting illegality...", "Compiling..."],
      epc: ["Scanning thermal...", "Checking mandates...", "Calculating..."]
    };
    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;
    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1500);
    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);
    setFeedbackGiven(false);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      try {
        if (mode === 'contract') res = await analyzeContract(base64);
        else if (mode === 'bidding') res = await detectBiddingWar(base64);
        else res = await analyzeEPC(base64);
      } catch (e) {
        res = { isSafe: false, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);

      const historyItem: ScanHistoryItem = {
        id: Date.now().toString(),
        date: Date.now(),
        type: mode,
        summary: res.summary || res.evidence || "Scan completed",
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk'
      };
      onSaveHistory(historyItem);
    };
    reader.readAsDataURL(file);
  };

  const submitFeedback = () => {
    setFeedbackGiven(true);
    setTimeout(() => alert("Thanks! Your feedback helps train our Legal Guardian AI."), 300);
  };

  const getIconForType = (type: string) => {
    switch(type) {
      case 'contract': return <FileText className="w-5 h-5 text-neone-blue" />;
      case 'bidding': return <MessageSquare className="w-5 h-5 text-neone-yellow" />;
      case 'epc': return <Thermometer className="w-5 h-5 text-neone-green" />;
      default: return <Scan className="w-5 h-5" />;
    }
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h2 className="font-display text-3xl font-bold">Compliance Pulse</h2>
        <button 
          onClick={() => setView(view === 'scan' ? 'history' : 'scan')} 
          className="flex items-center gap-2 px-4 py-2 bg-gray-200 dark:bg-gray-700 rounded-full font-bold text-sm hover:bg-black hover:text-white dark:hover:bg-white dark:hover:text-black transition-colors"
        >
           {view === 'scan' ? <History className="w-4 h-4" /> : <Scan className="w-4 h-4" />}
           {view === 'scan' ? 'History' : 'Scanner'}
        </button>
      </div>

      {view === 'history' ? (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-4">
           {history.length === 0 && (
             <div className="text-center py-10">
               <History className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-2" />
               <p className="text-gray-500">No scan history yet.</p>
             </div>
           )}
           {history.map(item => (
             <SoftCard key={item.id} className="border-l-4 border-l-gray-300 dark:border-l-gray-500">
                <div className="flex justify-between items-start">
                  <div className="flex gap-3">
                    <div className="bg-gray-100 dark:bg-gray-700 p-2 rounded-lg h-fit">
                      {getIconForType(item.type)}
                    </div>
                    <div>
                      <span className="text-xs uppercase font-bold text-gray-400">{item.type}</span>
                      <h4 className="font-bold">{format(item.date, 'dd MMM yyyy')} <span className="text-gray-400 text-xs font-normal">at {format(item.date, 'HH:mm')}</span></h4>
                    </div>
                  </div>
                  <span className={`px-2 py-0.5 rounded text-xs font-bold ${item.status === 'safe' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                    {item.status.toUpperCase()}
                  </span>
                </div>
                <p className="text-sm mt-3 text-gray-600 dark:text-gray-300 bg-gray-50 dark:bg-gray-900/50 p-3 rounded">{item.summary}</p>
             </SoftCard>
           ))}
        </motion.div>
      ) : (
        <>
          <div className="flex gap-2 p-1 bg-gray-200 dark:bg-gray-700 rounded-lg">
            {['contract', 'bidding', 'epc'].map((m) => (
              <button
                key={m}
                onClick={() => { setMode(m as any); setResult(null); }}
                className={`flex-1 py-2 text-sm font-bold rounded-md capitalize transition-all ${mode === m ? 'bg-white dark:bg-gray-800 shadow-sm text-black dark:text-white' : 'text-gray-500 dark:text-gray-400'}`}
              >
                {m === 'epc' ? 'EPC Shield' : m}
              </button>
            ))}
          </div>

          <div className="relative h-fit min-h-[16rem] bg-neone-dark rounded-xl border-2 border-black dark:border-white overflow-hidden flex flex-col items-center justify-center text-white">
            {scanning && (
              <motion.div 
                className="absolute top-0 left-0 w-full h-1 bg-neone-green shadow-[0_0_15px_rgba(6,214,160,0.8)] z-10"
                animate={{ top: ['0%', '100%', '0%'] }}
                transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
              />
            )}

            {!result && !scanning && (
              <div className="text-center p-6 w-full h-64 flex flex-col items-center justify-center">
                <Camera className="w-12 h-12 mx-auto mb-4 text-gray-400" />
                <p className="mb-4 text-gray-300">
                  {mode === 'epc' ? 'Scan radiator, window or room' : `Upload a photo of your ${mode}`}
                </p>
                <NeuButton onClick={() => fileInputRef.current?.click()} variant="secondary" className="w-full">
                  <Upload className="w-4 h-4 mr-2" /> Select Image
                </NeuButton>
                <input 
                  ref={fileInputRef} 
                  type="file" 
                  accept="image/*" 
                  className="hidden" 
                  onChange={handleFileUpload} 
                />
              </div>
            )}

            {scanning && (
              <div className="flex flex-col items-center justify-center h-64 px-8 text-center w-full">
                <Scan className="w-12 h-12 text-neone-green animate-pulse mb-4" />
                 <AnimatePresence mode="wait">
                    <motion.div
                        key={loadingMessage}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ duration: 0.2 }}
                        className="w-full"
                    >
                       <p className="font-mono text-neone-green font-bold text-sm leading-tight">
                        {loadingMessage.toUpperCase()}
                       </p>
                    </motion.div>
                 </AnimatePresence>
              </div>
            )}

            {result && !scanning && (
              <div className="w-full bg-white dark:bg-gray-800 text-black dark:text-white p-6">
                 <div className="flex justify-between items-start mb-4">
                    <div>
                      {mode === 'contract' && (
                        <div className="flex items-center gap-4">
                           <div className={`w-16 h-16 rounded-full flex items-center justify-center text-2xl font-bold border-4 ${result.score > 80 ? 'border-neone-green text-neone-green' : result.score > 50 ? 'border-yellow-400 text-yellow-500' : 'border-neone-red text-neone-red'}`}>
                              {result.score || '?'}
                           </div>
                           <div>
                              <div className="text-xs text-gray-500 uppercase font-bold">Health Score</div>
                              <div className={`text-xl font-bold ${result.isSafe ? 'text-neone-green' : 'text-neone-red'}`}>
                                {result.isSafe ? 'LEGALLY SOUND' : 'RISK DETECTED'}
                              </div>
                           </div>
                        </div>
                      )}
                      {mode === 'bidding' && (
                        <h3 className={`text-2xl font-display font-bold mb-2 ${result.isIllegal ? 'text-neone-red' : 'text-neone-green'}`}>
                          {result.isIllegal ? 'ILLEGAL BIDDING' : 'NO VIOLATION'}
                        </h3>
                      )}
                      {mode === 'epc' && (
                         <h3 className={`text-2xl font-display font-bold mb-2 ${result.compliance ? 'text-neone-green' : 'text-neone-red'}`}>
                           RATING: {result.score}
                         </h3>
                      )}
                    </div>
                    <button onClick={() => setResult(null)} className="text-gray-400 hover:text-black dark:hover:text-white">
                      <XCircle />
                    </button>
                 </div>

                <p className="mb-4 text-sm text-gray-700 dark:text-gray-300 bg-gray-50 dark:bg-gray-900 p-3 rounded">{result.summary || result.evidence}</p>

                {!feedbackGiven ? (
                  <div className="mt-6 pt-4 border-t border-gray-100 dark:border-gray-700">
                    <p className="text-xs font-bold text-gray-500 mb-2">WAS THIS SCAN ACCURATE?</p>
                    <div className="flex gap-2">
                       <button onClick={submitFeedback} className="flex-1 bg-gray-100 dark:bg-gray-700 hover:bg-green-100 dark:hover:bg-green-900/30 p-2 rounded flex justify-center items-center gap-2 transition-colors">
                          <ThumbsUp className="w-4 h-4 text-green-600" /> <span className="text-xs font-bold">Yes</span>
                       </button>
                       <button onClick={submitFeedback} className="flex-1 bg-gray-100 dark:bg-gray-700 hover:bg-red-100 dark:hover:bg-red-900/30 p-2 rounded flex justify-center items-center gap-2 transition-colors">
                          <AlertTriangle className="w-4 h-4 text-red-600" /> <span className="text-xs font-bold">No</span>
                       </button>
                    </div>
                  </div>
                ) : (
                  <div className="mt-6 pt-4 border-t border-gray-100 dark:border-gray-700 text-center">
                    <p className="text-xs font-bold text-neone-green">FEEDBACK SUBMITTED</p>
                  </div>
                )}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

