export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.HOME);
  const [locationName, setLocationName] = useState('Locating...');
  const [darkMode, setDarkMode] = useState(false);
  const [scanHistory, setScanHistory] = useState<ScanHistoryItem[]>([]);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    const handleLocation = (lat: number, lng: number) => {
      const isAtOldStreet = Math.abs(lat - 51.5262) < 0.01 && Math.abs(lng - (-0.0847)) < 0.01;

      if (isAtOldStreet) {
        setLocationName("Old Street, EC1V");
      } else {
        if (lat > 51.4 && lat < 51.7 && lng > -0.5 && lng < 0.2) {
          setLocationName("Hackney, London");
        } else {
          setLocationName("Old Street, EC1V");
        }
      }
    };

    if (navigator.geolocation && isAuthenticated) {
      navigator.geolocation.getCurrentPosition(
        (pos) => handleLocation(pos.coords.latitude, pos.coords.longitude),
        () => setLocationName("Old Street, EC1V")
      );
    } else if (isAuthenticated) {
       setLocationName("Old Street, EC1V");
    }
  }, [isAuthenticated]);

  const addToHistory = (item: ScanHistoryItem) => {
    setScanHistory(prev => [item, ...prev]);
  };

  if (!isAuthenticated) {
    return <LoginView onLogin={() => setIsAuthenticated(true)} />;
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-neone-dark text-black dark:text-white font-sans selection:bg-neone-blue selection:text-white transition-colors duration-300">
      <main className="max-w-md mx-auto min-h-screen bg-white dark:bg-black shadow-2xl overflow-hidden relative border-x border-gray-100 dark:border-gray-800">
        <div className="h-full overflow-y-auto p-6 pb-32 scroll-smooth">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, x: 10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -10 }}
              transition={{ duration: 0.2 }}
            >
              {activeTab === AppTab.HOME && <HomeView location={locationName} setTab={setActiveTab} />}
              {activeTab === AppTab.SCAN && <ScannerView onSaveHistory={addToHistory} history={scanHistory} />}
              {activeTab === AppTab.TRACKER && <TrackerView />}
              {activeTab === AppTab.PROTECT && <ProtectView />}
              {activeTab === AppTab.PROFILE && <ProfileView onLogout={() => setIsAuthenticated(false)} darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)} />}
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Bottom Navigation */}
        <div className="absolute bottom-0 left-0 w-full bg-white/90 dark:bg-black/90 backdrop-blur-md border-t-2 border-black dark:border-white z-50">
          <div className="flex justify-around items-center h-20 pb-2">
            <button 
              onClick={() => setActiveTab(AppTab.HOME)} 
              className={`flex flex-col items-center p-2 transition-transform active:scale-95 ${activeTab === AppTab.HOME ? 'text-neone-blue' : 'text-gray-400 dark:text-gray-500'}`}
            >
              <HomeIcon strokeWidth={3} className="w-6 h-6 mb-1" />
              <span className="text-[10px] font-bold uppercase">Home</span>
            </button>
            <button 
              onClick={() => setActiveTab(AppTab.SCAN)}
              className={`flex flex-col items-center p-2 transition-transform active:scale-95 ${activeTab === AppTab.SCAN ? 'text-neone-blue' : 'text-gray-400 dark:text-gray-500'}`}
            >
              <Scan strokeWidth={3} className="w-6 h-6 mb-1" />
              <span className="text-[10px] font-bold uppercase">Pulse</span>
            </button>

            <div className="relative -top-6">
              <button 
                onClick={() => setActiveTab(AppTab.TRACKER)}
                className={`w-14 h-14 rounded-full border-2 border-black dark:border-white bg-neone-red text-white flex items-center justify-center shadow-neu dark:shadow-neu-white transition-all active:translate-y-1 active:shadow-none hover:scale-105`}
              >
                 <Shield strokeWidth={3} className="w-8 h-8" />
              </button>
            </div>

            <button 
              onClick={() => setActiveTab(AppTab.PROTECT)}
              className={`flex flex-col items-center p-2 transition-transform active:scale-95 ${activeTab === AppTab.PROTECT ? 'text-neone-blue' : 'text-gray-400 dark:text-gray-500'}`}
            >
              <FileText strokeWidth={3} className="w-6 h-6 mb-1" />
              <span className="text-[10px] font-bold uppercase">Legal</span>
            </button>

            <button 
              onClick={() => setActiveTab(AppTab.PROFILE)}
              className={`flex flex-col items-center p-2 transition-transform active:scale-95 ${activeTab === AppTab.PROFILE ? 'text-neone-blue' : 'text-gray-400 dark:text-gray-500'}`}
            >
               <User strokeWidth={3} className="w-6 h-6 mb-1" />
               <span className="text-[10px] font-bold uppercase">Me</span>
            </button>
          </div>
        </div>
      </main>
    </div>
  );
}

