const LoginView = ({ onLogin }: { onLogin: () => void }) => {
  const [pin, setPin] = useState('');
  const [mode, setMode] = useState<'login' | 'setup' | 'confirm'>('login');
  const [setupPin, setSetupPin] = useState('');
  const [storedPin, setStoredPin] = useState<string | null>(localStorage.getItem('rentshield_pin'));
  const [error, setError] = useState(false);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  useEffect(() => {
    if (!storedPin) {
      setMode('setup');
    }
  }, [storedPin]);

  const handleNum = (num: string) => {
    const current = pin + num;
    if (current.length <= 4) {
      setPin(current);
      if (current.length === 4) {
        if (mode === 'login') {
          if (current === storedPin || current === '2026') { // '2026' is master bypass
             setTimeout(onLogin, 200);
          } else {
             triggerError();
          }
        } else if (mode === 'setup') {
          setSetupPin(current);
          setPin('');
          setMode('confirm');
        } else if (mode === 'confirm') {
          if (current === setupPin) {
            localStorage.setItem('rentshield_pin', current);
            setStoredPin(current);
            setMode('login');
            setPin('');
            alert('PIN Set Successfully!');
          } else {
            triggerError();
          }
        }
      }
    }
  };

  const triggerError = () => {
    setError(true);
    setTimeout(() => {
      setPin('');
      setError(false);
    }, 500);
  };

  const handleBiometric = () => {
    if (mode !== 'login') return;
    setIsAuthenticating(true);
    // Simulate thumb scanner UI behavior
    setTimeout(() => {
      setIsAuthenticating(false);
      onLogin();
    }, 1200);
  };

  const getTitle = () => {
    if (mode === 'setup') return "Set your Security PIN";
    if (mode === 'confirm') return "Confirm your PIN";
    return "Enter your Security PIN";
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-neone-dark flex flex-col items-center justify-center p-6 relative overflow-hidden transition-colors">
      <div className="absolute top-[-20%] left-[-20%] w-[140%] h-[140%] bg-[radial-gradient(circle_at_50%_50%,rgba(0,209,255,0.05),transparent_70%)] pointer-events-none" />

      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full max-w-sm"
      >
        <div className="mb-8 text-center">
          <div className="w-16 h-16 bg-neone-green border-2 border-black dark:border-white shadow-neu dark:shadow-neu-white rounded-xl flex items-center justify-center mx-auto mb-6">
            <Shield className="w-8 h-8 text-black" />
          </div>
          <h1 className="font-display text-4xl font-bold text-black dark:text-white mb-2">
            Rent<span className="text-neone-red">Shield</span>
          </h1>
          <p className="text-gray-500 dark:text-gray-400 font-medium">{getTitle()}</p>
        </div>

        {/* PIN Dots */}
        <div className="flex justify-center gap-6 mb-12">
          {[0, 1, 2, 3].map(i => (
            <motion.div
              key={i}
              animate={error ? { x: [-10, 10, -10, 10, 0] } : {}}
              className={`w-4 h-4 rounded-full border-2 border-black dark:border-white transition-colors duration-200 ${
                pin.length > i ? 'bg-black dark:bg-white' : 'bg-transparent'
              } ${error ? 'border-neone-red bg-neone-red' : ''}`}
            />
          ))}
        </div>

        {/* Keypad */}
        <div className="grid grid-cols-3 gap-y-4 gap-x-8 mb-10 px-4">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
            <button
              key={n}
              onClick={() => handleNum(n.toString())}
              className="h-16 w-16 mx-auto rounded-full text-2xl font-bold font-display text-black dark:text-white hover:bg-gray-200 dark:hover:bg-gray-800 active:scale-95 transition-all outline-none focus:outline-none flex items-center justify-center"
            >
              {n}
            </button>
          ))}
          <div className="flex items-center justify-center">
             <motion.button 
                onClick={handleBiometric}
                disabled={isAuthenticating || mode !== 'login'}
                animate={isAuthenticating ? { scale: [1, 1.2, 1], opacity: [1, 0.5, 1] } : {}}
                className={`w-16 h-16 flex items-center justify-center rounded-full transition-all ${isAuthenticating ? 'bg-neone-blue' : 'hover:bg-gray-100 dark:hover:bg-gray-800'} ${mode !== 'login' ? 'opacity-20 pointer-events-none' : ''}`}
             >
                {isAuthenticating ? <Loader2 className="w-8 h-8 animate-spin text-white" /> : <Fingerprint className="w-8 h-8 text-neone-blue" />}
             </motion.button>
          </div>
          <button
              onClick={() => handleNum('0')}
              className="h-16 w-16 mx-auto rounded-full text-2xl font-bold font-display text-black dark:text-white hover:bg-gray-200 dark:hover:bg-gray-800 active:scale-95 transition-all flex items-center justify-center"
            >
              0
          </button>
          <div className="flex items-center justify-center">
            {pin.length > 0 ? (
              <button
                onClick={() => setPin(pin.slice(0, -1))}
                className="w-16 h-16 flex items-center justify-center text-black dark:text-white active:scale-95 transition-transform"
              >
                <ChevronLeft className="w-8 h-8" />
              </button>
            ) : mode === 'login' && (
              <button 
                onClick={() => setMode('setup')}
                className="text-[10px] font-bold uppercase text-gray-400 hover:text-black dark:hover:text-white transition-colors"
              >
                Reset PIN
              </button>
            )}
          </div>
        </div>
      </motion.div>
    </div>
  )
}

