            )}

            {!result && !scanning && (
              <div className="text-center p-6 w-full h-64 flex flex-col items-center justify-center">
                <Camera className="w-12 h-12 mx-auto mb-4 text-gray-400" />
                <p className="mb-4 text-gray-300">
                  {mode === 'epc' ? 'Scan radiator, window or room' : `Upload a photo of your ${mode}`}
                </p>
                <NeuButton onClick={() => fileInputRef.current?.click()} variant="secondary" className="w-full">
                  <Upload className="w-4 h-4 mr-2" /> Select Image
                </NeuButton>
                <input 
                  ref={fileInputRef} 
                  type="file" 
                  accept="image/*" 
                  className="hidden" 
                  onChange={handleFileUpload} 
                />
              </div>
            )}

            {scanning && (
              <div className="flex flex-col items-center justify-center h-64 px-8 text-center w-full">
                <Scan className="w-12 h-12 text-neone-green animate-pulse mb-4" />
                 <AnimatePresence mode="wait">
                    <motion.div
                        key={loadingMessage}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ duration: 0.2 }}
                        className="w-full"
                    >
                       <p className="font-mono text-neone-green font-bold text-sm leading-tight">
                        {loadingMessage.toUpperCase()}
                       </p>
                    </motion.div>
                 </AnimatePresence>
              </div>
            )}

            {result && !scanning && (
              <div className="w-full bg-white dark:bg-gray-800 text-black dark:text-white p-6">
                 <div className="flex justify-between items-start mb-4">
                    <div>
                      {mode === 'contract' && (
                        <div className="flex items-center gap-4">
                           <div className={`w-16 h-16 rounded-full flex items-center justify-center text-2xl font-bold border-4 ${result.score > 80 ? 'border-neone-green text-neone-green' : result.score > 50 ? 'border-yellow-400 text-yellow-500' : 'border-neone-red text-neone-red'}`}>
                              {result.score || '?'}
                           </div>
                           <div>
                              <div className="text-xs text-gray-500 uppercase font-bold">Health Score</div>
                              <div className={`text-xl font-bold ${result.isSafe ? 'text-neone-green' : 'text-neone-red'}`}>
                                {result.isSafe ? 'LEGALLY SOUND' : 'RISK DETECTED'}
                              </div>
                           </div>
                        </div>
                      )}
                      {mode === 'bidding' && (
                        <h3 className={`text-2xl font-display font-bold mb-2 ${result.isIllegal ? 'text-neone-red' : 'text-neone-green'}`}>
                          {result.isIllegal ? 'ILLEGAL BIDDING' : 'NO VIOLATION'}
                        </h3>
                      )}
                      {mode === 'epc' && (
                         <h3 className={`text-2xl font-display font-bold mb-2 ${result.compliance ? 'text-neone-green' : 'text-neone-red'}`}>
                           RATING: {result.score}
                         </h3>
                      )}
                    </div>
                    <button onClick={() => setResult(null)} className="text-gray-400 hover:text-black dark:hover:text-white">
                      <XCircle />
                    </button>
                 </div>

                <p className="mb-4 text-sm text-gray-700 dark:text-gray-300 bg-gray-50 dark:bg-gray-900 p-3 rounded">{result.summary || result.evidence}</p>

                {!feedbackGiven ? (
                  <div className="mt-6 pt-4 border-t border-gray-100 dark:border-gray-700">
                    <p className="text-xs font-bold text-gray-500 mb-2">WAS THIS SCAN ACCURATE?</p>
