                       <button onClick={submitFeedback} className="flex-1 bg-gray-100 dark:bg-gray-700 hover:bg-green-100 dark:hover:bg-green-900/30 p-2 rounded flex justify-center items-center gap-2 transition-colors">
                          <ThumbsUp className="w-4 h-4 text-green-600" /> <span className="text-xs font-bold">Yes</span>
                       </button>
                       <button onClick={submitFeedback} className="flex-1 bg-gray-100 dark:bg-gray-700 hover:bg-red-100 dark:hover:bg-red-900/30 p-2 rounded flex justify-center items-center gap-2 transition-colors">
                          <AlertTriangle className="w-4 h-4 text-red-600" /> <span className="text-xs font-bold">No</span>
                       </button>
                    </div>
                  </div>
                ) : (
                  <div className="mt-6 pt-4 border-t border-gray-100 dark:border-gray-700 text-center">
                    <p className="text-xs font-bold text-neone-green">FEEDBACK SUBMITTED</p>
                  </div>
                )}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

const TrackerView = () => {
  const [hazards, setHazards] = useState<Hazard[]>([
    {
      id: '1',
      type: 'Black Mould',
      description: 'Found in bedroom corner, approx 1m wide.',
      severity: 'High',
      dateReported: Date.now() - 1000 * 60 * 60 * 24 * 13, // 13 days ago
      status: 'Landlord Notified'
    }
  ]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const enableNotifications = async () => {
    if ("Notification" in window) {
      const permission = await Notification.requestPermission();
      if (permission === "granted") {
        new Notification("RentShield Alerts Enabled", { body: "We will notify you when action timers expire." });
      } else {
        alert("Permission denied. You can enable this in your browser settings.");
      }
    } else {
       alert("Your browser does not support notifications.");
    }
  };

  const handleAddHazard = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const analysis = await analyzeHazard(base64);

      const newHazard: Hazard = {
        id: Math.random().toString(36).substr(2, 9),
        type: analysis.type,
        description: analysis.description,
        severity: analysis.severity,
        dateReported: Date.now(),
        status: 'Reported',
        imageUrl: URL.createObjectURL(file)
      };
      setHazards([newHazard, ...hazards]);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-end">
        <h2 className="font-display text-3xl font-bold">Awaab's Law<br/>Tracker</h2>
        <div className="flex gap-2">
          <button onClick={enableNotifications} className="w-10 h-10 rounded-full bg-gray-200 dark:bg-gray-700 flex items-center justify-center">
             <Bell className="w-5 h-5" />
          </button>
          <NeuButton onClick={() => fileInputRef.current?.click()} className="h-10 px-4 text-sm">
            + Log
          </NeuButton>
        </div>
        <input ref={fileInputRef} type="file" className="hidden" onChange={handleAddHazard} />
      </div>

      <div className="space-y-4">
        {hazards.map(h => {
          const daysElapsed = differenceInDays(Date.now(), h.dateReported);
          const daysLeft = 14 - daysElapsed;
          const progress = Math.min((daysElapsed / 14) * 100, 100);

          return (
            <SoftCard key={h.id} className="relative overflow-hidden border-2 border-transparent hover:border-black dark:hover:border-white transition-all">
              <div className="flex justify-between items-start mb-3">
                <div>
                  <span className={`inline-block px-2 py-1 text-xs font-bold uppercase rounded mb-2 ${
                    h.severity === 'Critical' || h.severity === 'High' ? 'bg-red-100 text-red-800' : 'bg-yellow-100 text-yellow-800'
                  }`}>
                    {h.severity} Priority
                  </span>
                  <h3 className="font-bold text-lg">{h.type}</h3>
                </div>
                <div className="text-right">
                   <div className="text-xs uppercase font-bold text-gray-400 mb-1">Legal Timeline</div>
                   <div className="flex items-center gap-1 text-xs font-bold">
                      <span className="text-gray-500">Day {daysElapsed}</span>
                      <span className="text-gray-300">/</span>
                      <span className="text-neone-red">14</span>
                   </div>
                </div>
              </div>

              {/* Visual Timeline Bar */}
              <div className="w-full h-3 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden mb-4 relative">
                 <motion.div 
                   className={`h-full ${daysLeft <= 2 ? 'bg-neone-red' : 'bg-neone-blue'}`} 
                   initial={{ width: 0 }} 
                   animate={{ width: `${progress}%` }} 
                 />
              </div>

              <div className="flex justify-between text-xs text-gray-500 mb-4 px-1">
                 <div>Reported<br/>{format(h.dateReported, 'dd MMM')}</div>
                 <div className="text-right">Deadline<br/>{format(addDays(h.dateReported, 14), 'dd MMM')}</div>
              </div>

              <p className="text-sm text-gray-600 dark:text-gray-300 mb-4 bg-gray-50 dark:bg-gray-900 p-2 rounded">{h.description}</p>

              <div className="flex gap-2">
                 {daysLeft <= 0 ? (
                   <NeuButton variant="danger" className="w-full text-sm py-2 animate-pulse">
                     <Siren className="w-4 h-4 mr-2" /> GENERATE OMBUDSMAN REPORT
                   </NeuButton>
                 ) : (
                   <div className="w-full bg-gray-100 dark:bg-gray-700 rounded h-10 flex items-center justify-center text-xs font-bold text-gray-400 dark:text-gray-500 border border-gray-200 dark:border-gray-600">
                     <Clock className="w-3 h-3 mr-2" /> Action unlocks in {daysLeft} days
                   </div>
                 )}
              </div>
            </SoftCard>
          );
        })}
      </div>
    </div>
  );
};

const ProtectView = () => {
  const [activeTool, setActiveTool] = useState<'response' | 'deposit' | 'rent' | 'translate'>('rent');

  // States for various tools
  const [context, setContext] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [depositDate, setDepositDate] = useState('');
  const [depositAmount, setDepositAmount] = useState('');
  const [currentRent, setCurrentRent] = useState('');
  const [newRent, setNewRent] = useState('');
  const [rentAdvice, setRentAdvice] = useState<any>(null);
  const [landlordText, setLandlordText] = useState('');
  const [translation, setTranslation] = useState<any>(null);

  const handleGenerateResponse = async (tone: Tone) => {
    if (!context) return;
    setLoading(true);
    const res = await generateResponse(tone, context);
    setResponse(res);
    setLoading(false);
  };

  const handleRentCalc = async () => {
    if(!currentRent || !newRent) return;
    setLoading(true);
    const res = await analyzeRentIncrease(Number(currentRent), Number(newRent), "Old Street, London");
    setRentAdvice(res);
    setLoading(false);
  };

  const handleTranslate = async () => {
    if(!landlordText) return;
    setLoading(true);
    const res = await translateLandlordSpeak(landlordText);
    setTranslation(res);
    setLoading(false);
  };

  const getDeadline = () => {
    if (!depositDate) return null;
    return format(addDays(new Date(depositDate), 30), 'dd MMM yyyy');
  }

  return (
    <div className="space-y-6 pb-24">
