             <button
                key={tool.id}
                onClick={() => setActiveTool(tool.id as any)}
                className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap font-bold text-sm transition-all ${activeTool === tool.id ? 'bg-black text-white dark:bg-white dark:text-black' : 'bg-gray-200 dark:bg-gray-800 text-gray-500'}`}
             >
                <tool.icon size={14} />
                {tool.label}
             </button>
          ))}
       </div>

       {/* RENT SPIKE CALCULATOR */}
       {activeTool === 'rent' && (
         <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
            <SoftCard>
               <h3 className="font-bold text-lg font-display mb-4">Rent Spike Calculator</h3>
               <div className="grid grid-cols-2 gap-4 mb-4">
                 <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">CURRENT RENT</label>
