                    </div>
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">PROPOSED RENT</label>
                    <div className="relative">
                       <span className="absolute left-3 top-2.5 text-gray-400">£</span>
                       <input type="number" value={newRent} onChange={e => setNewRent(e.target.value)} className="w-full pl-8 py-2 bg-gray-50 dark:bg-gray-900 border rounded font-bold" />
                    </div>
                 </div>
               </div>
               <NeuButton className="w-full mb-4" onClick={handleRentCalc} isLoading={loading}>Check Fairness</NeuButton>

               {rentAdvice && (
                 <div className="mt-4 p-4 bg-gray-100 dark:bg-gray-700 rounded-xl">
                    <div className={`text-xl font-bold mb-2 ${rentAdvice.isFair ? 'text-neone-green' : 'text-neone-red'}`}>
