                    <input type="date" className="w-full px-3 py-2 bg-gray-50 dark:bg-gray-900 border rounded font-bold text-xs" value={depositDate} onChange={(e) => setDepositDate(e.target.value)} />
                 </div>
               </div>

               {depositDate && (
                 <div className="bg-gray-100 dark:bg-gray-700 p-3 rounded mb-6 flex justify-between items-center">
                    <span className="text-sm font-bold text-gray-600 dark:text-gray-300">Deadline:</span>
                    <span className="text-sm font-bold text-black bg-white dark:bg-gray-900 dark:text-white px-2 py-1 rounded border border-gray-200 dark:border-gray-600">
                      {getDeadline()}
                    </span>
                 </div>
               )}

               <div className="space-y-3">
                 <p className="text-sm font-bold mb-2">Verify with Schemes:</p>
                 {['DPS', 'TDS', 'MyDeposits'].map(scheme => (
                    <div key={scheme} className="flex items-center justify-between p-3 border-2 border-gray-200 dark:border-gray-600 rounded hover:border-black dark:hover:border-white transition-all cursor-pointer">
                      <span className="font-bold text-sm">Check {scheme}</span>
                      <ExternalLink className="w-4 h-4 text-gray-400" />
