                    <div className="bg-white dark:bg-gray-800 p-2 rounded h-fit shadow-sm">
                        <Calculator className="w-6 h-6 text-neone-red" />
                    </div>
                    <div>
                        <h3 className="font-bold text-md mb-1">Compensation Estimate</h3>
                        {depositAmount ? (
