                    </div>
                </div>
            </SoftCard>
         </motion.div>
       )}

       {/* EMAIL GENERATOR */}
       {activeTool === 'response' && (
         <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
           <SoftCard>
             <label className="block text-sm font-bold mb-2">Context</label>
