                    <motion.div layout key={notif.id} className={`bg-${notif.type === 'danger' ? 'red' : 'blue'}-50 dark:bg-${notif.type === 'danger' ? 'red' : 'blue'}-900/20 p-4 border-l-4 border-neone-${notif.type === 'danger' ? 'red' : 'blue'} rounded-r-lg relative group`}>
