    );

    if (activeSection === 'help') return (
        <div className="space-y-6">
             <button onClick={() => setActiveSection('main')} className="flex items-center gap-2 text-gray-500 hover:text-black dark:hover:text-white"><ChevronLeft className="w-5 h-5" /> Back</button>
