                         <span className="font-bold text-sm">Local Council Advice</span>
                         <ExternalLink size={14} />
                     </a>
                 </div>
             </SoftCard>
        </div>
    );

    // Default fallback
    return <div />;
  };

  return (
    <div className="space-y-6 pb-24">
