const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [view, setView] = useState<'scan' | 'history'>('scan');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const [feedbackGiven, setFeedbackGiven] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;
    const messages = {
      contract: ["Analyzing clauses...", "Checking 2026 Act...", "Validating...", "Identifying Hazards..."],
      bidding: ["Checking patterns...", "Detecting illegality...", "Compiling..."],
      epc: ["Scanning thermal...", "Checking mandates...", "Calculating..."]
    };
    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;
    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1500);
    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);
    setFeedbackGiven(false);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      try {
        if (mode === 'contract') res = await analyzeContract(base64);
        else if (mode === 'bidding') res = await detectBiddingWar(base64);
        else res = await analyzeEPC(base64);
      } catch (e) {
        res = { isSafe: false, score: 0, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);

      const historyItem: ScanHistoryItem = {
        id: Date.now().toString(),
        date: Date.now(),
        type: mode,
        summary: res.summary || res.evidence || "Scan completed",
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk'
      };
      onSaveHistory(historyItem);
    };
    reader.readAsDataURL(file);
  };

  const simulateIllegalContract = () => {
    setScanning(true);
    setResult(null);
    setLoadingMessage("IDENTIFYING LEGAL HAZARDS...");
    setTimeout(() => {
      const mockResult = {
        isSafe: false,
        score: 34,
        summary: "This contract contains several severe legal hazards that violate the Renters' Rights Act 2026.",
        issues: [
          "Section 21 'No-Fault' Eviction Clause found on Page 4.",
          "Illegal 'Fixed-Term' minimum period of 12 months specified.",
          "Unauthorized 'Professional Cleaning' fee listed in Section 8.",
          "Missing Mandatory Ombudsman Registration reference."
        ]
      };
      setResult(mockResult);
      setScanning(false);
      addToHistoryFromMock('contract', mockResult);
    }, 3000);
  };

  const addToHistoryFromMock = (type: any, res: any) => {
      const historyItem: ScanHistoryItem = {
        id: Date.now().toString(),
        date: Date.now(),
        type: type,
        summary: res.summary || "Scan completed",
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk'
      };
      onSaveHistory(historyItem);
  };

  const submitFeedback = () => {
    setFeedbackGiven(true);
    setTimeout(() => alert("Thanks! Your feedback helps train our Legal Guardian AI."), 300);
  };

