              placeholder="e.g. Landlord is ignoring my mould complaint..."
              value={context}
              onChange={(e) => setContext(e.target.value)}
             />

             <div className="grid grid-cols-1 gap-2 mt-4">
               {Object.values(Tone).map(t => (
                 <NeuButton 
                    key={t} 
                    variant="secondary" 
                    onClick={() => handleGenerateResponse(t)}
                    disabled={!context || loading}
                    className="text-sm py-2"
                  >
                   Generate {t}
                 </NeuButton>
               ))}
             </div>
           </SoftCard>

           {loading && <div className="flex justify-center p-8"><Loader2 className="animate-spin w-8 h-8 text-neone-blue" /></div>}
           {response && (
             <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
                <div className="bg-white dark:bg-gray-800 border-2 border-black dark:border-white shadow-neu dark:shadow-neu-white p-4 relative">
