                  <div className="whitespace-pre-wrap text-sm font-sans text-gray-700 dark:text-gray-300 leading-relaxed">
                    {response}
                  </div>
                  <NeuButton variant="primary" className="mt-4 w-full text-sm" onClick={() => {navigator.clipboard.writeText(response); alert('Copied!')}}>
                    Copy to Clipboard
                  </NeuButton>
                </div>
             </motion.div>
           )}
         </motion.div>
       )}
    </div>
  );
};

