  const [locationName, setLocationName] = useState('Locating...');
  const [darkMode, setDarkMode] = useState(false);
  const [scanHistory, setScanHistory] = useState<ScanHistoryItem[]>([]);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    const handleLocation = (lat: number, lng: number) => {
      const isAtOldStreet = Math.abs(lat - 51.5262) < 0.01 && Math.abs(lng - (-0.0847)) < 0.01;

      if (isAtOldStreet) {
        setLocationName("Old Street, EC1V");
      } else {
        if (lat > 51.4 && lat < 51.7 && lng > -0.5 && lng < 0.2) {
          setLocationName("Hackney, London");
        } else {
          setLocationName("Old Street, EC1V");
        }
      }
    };

    if (navigator.geolocation && isAuthenticated) {
      navigator.geolocation.getCurrentPosition(
        (pos) => handleLocation(pos.coords.latitude, pos.coords.longitude),
        () => setLocationName("Old Street, EC1V")
      );
    } else if (isAuthenticated) {
       setLocationName("Old Street, EC1V");
    }
  }, [isAuthenticated]);

  const addToHistory = (item: ScanHistoryItem) => {
    setScanHistory(prev => [item, ...prev]);
  };

  const handleChangePin = () => {
    if (window.confirm("Are you sure you want to change your PIN? You will be logged out to set a new one.")) {
      localStorage.removeItem('rentshield_pin');
      setIsAuthenticated(false);
