              exit={{ opacity: 0, x: -10 }}
              transition={{ duration: 0.2 }}
            >
              {activeTab === AppTab.HOME && <HomeView location={locationName} setTab={setActiveTab} />}
              {activeTab === AppTab.SCAN && <ScannerView onSaveHistory={addToHistory} history={scanHistory} />}
              {activeTab === AppTab.TRACKER && <TrackerView />}
              {activeTab === AppTab.PROTECT && <ProtectView />}
              {activeTab === AppTab.PROFILE && <ProfileView onLogout={() => setIsAuthenticated(false)} darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)} onChangePin={handleChangePin} />}
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Bottom Navigation */}
        <div className="absolute bottom-0 left-0 w-full bg-white/90 dark:bg-black/90 backdrop-blur-md border-t-2 border-black dark:border-white z-50">
          <div className="flex justify-around items-center h-20 pb-2">
