const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [view, setView] = useState<'scan' | 'history'>('scan');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const [feedbackGiven, setFeedbackGiven] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;
    const messages = {
      contract: ["Analyzing clauses...", "Checking 2026 Act...", "Validating...", "Identifying Legal Hazards..."],
      bidding: ["Checking patterns...", "Detecting bidding war...", "Compiling evidence..."],
      epc: ["Scanning thermal metrics...", "Checking 2026 mandates...", "Calculating efficiency..."]
    };
    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;
    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1500);
    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);
    setFeedbackGiven(false);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      try {
        if (mode === 'contract') res = await analyzeContract(base64);
        else if (mode === 'bidding') res = await detectBiddingWar(base64);
        else res = await analyzeEPC(base64);
      } catch (e) {
        res = { isSafe: false, score: 0, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);

      const historyItem: ScanHistoryItem = {
        id: Date.now().toString(),
        date: Date.now(),
        type: mode,
        summary: res.summary || res.evidence || "Scan completed",
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk'
      };
      onSaveHistory(historyItem);
    };
    reader.readAsDataURL(file);
  };

  const simulateIllegalContract = () => {
    setScanning(true);
    setResult(null);
    setLoadingMessage("IDENTIFYING LEGAL HAZARDS...");
    setTimeout(() => {
      const mockResult = {
        isSafe: false,
        score: 34,
        summary: "This contract contains several severe legal hazards that violate the Renters' Rights Act 2026.",
        issues: [
          "Illegal Section 21 'No-Fault' Eviction Clause found on Page 4.",
          "Illegal 'Fixed-Term' requirement (All tenancies must be periodic in 2026).",
          "Prohibited 'Professional Cleaning' fee listed in Section 8.",
          "Unfair 'Pets Prohibited' clause (Consent cannot be unreasonably withheld)."
        ]
      };
      setResult(mockResult);
      setScanning(false);

      const historyItem: ScanHistoryItem = {
        id: Date.now().toString(),
        date: Date.now(),
        type: 'contract',
        summary: mockResult.summary,
        status: 'risk'
      };
      onSaveHistory(historyItem);
    }, 3000);
  };

  const simulateBiddingWar = () => {
    setScanning(true);
    setResult(null);
    setLoadingMessage("DETECTING ILLEGAL BIDDING...");
    setTimeout(() => {
      const mockResult = {
        isIllegal: true,
        evidence: "Landlord: 'We have another offer for £1450. Can you match or beat it to secure the flat?'",
        summary: "Rental bidding identified. Asking for more than the advertised rent is illegal under Section 42 of the 2026 Act."
