      setResult(mockResult);
      setScanning(false);

      const historyItem: ScanHistoryItem = {
        id: Date.now().toString(),
        date: Date.now(),
        type: 'bidding',
        summary: mockResult.summary,
        status: 'risk'
      };
      onSaveHistory(historyItem);
    }, 3000);
  };

  const submitFeedback = () => {
    setFeedbackGiven(true);
    setTimeout(() => alert("Thanks! Your feedback helps train our Legal Guardian AI."), 300);
  };

  const getIconForType = (type: string) => {
    switch(type) {
      case 'contract': return <FileText className="w-5 h-5 text-neone-blue" />;
      case 'bidding': return <MessageSquare className="w-5 h-5 text-neone-yellow" />;
      case 'epc': return <Thermometer className="w-5 h-5 text-neone-green" />;
