          </div>

          <div className="relative h-fit min-h-[16rem] bg-neone-dark rounded-xl border-2 border-black dark:border-white overflow-hidden flex flex-col items-center justify-center text-white">
            {scanning && (
              <motion.div 
                className="absolute top-0 left-0 w-full h-1 bg-neone-green shadow-[0_0_15px_rgba(6,214,160,0.8)] z-10"
                animate={{ top: ['0%', '100%', '0%'] }}
