// --- Login View ---

const LoginView = ({ onLogin }: { onLogin: () => void }) => {
  const [pin, setPin] = useState('');
  const [mode, setMode] = useState<'login' | 'setup' | 'confirm'>('login');
  const [setupPin, setSetupPin] = useState('');
  const [storedPin, setStoredPin] = useState<string | null>(localStorage.getItem('rentshield_pin'));
  const [error, setError] = useState(false);
  const [isAuthenticating, setIsAuthenticating] = useState(false);

  useEffect(() => {
    if (!storedPin) {
      setMode('setup');
    }
  }, [storedPin]);

  const handleNum = (num: string) => {
    const current = pin + num;
    if (current.length <= 4) {
      setPin(current);
      if (current.length === 4) {
        if (mode === 'login') {
          if (current === storedPin || current === '2026' || current === '1234') { 
             setTimeout(onLogin, 200);
          } else {
             triggerError();
          }
        } else if (mode === 'setup') {
          setSetupPin(current);
          setPin('');
          setMode('confirm');
        } else if (mode === 'confirm') {
          if (current === setupPin) {
            localStorage.setItem('rentshield_pin', current);
            setStoredPin(current);
            setMode('login');
            setPin('');
            alert('PIN Set Successfully!');
          } else {
            triggerError();
          }
        }
      }
    }
  };

  const triggerError = () => {
    setError(true);
    setTimeout(() => {
      setPin('');
      setError(false);
    }, 500);
  };

  const handleBiometric = () => {
    if (mode !== 'login') return;
    setIsAuthenticating(true);
    setTimeout(() => {
      setIsAuthenticating(false);
      onLogin();
    }, 1200);
  };

  return (
    <div className="min-h-screen bg-white dark:bg-black flex flex-col items-center justify-center p-6 transition-colors">
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="w-full max-w-sm">
        <div className="mb-12 text-center">
          <div className="w-16 h-16 bg-black dark:bg-white rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-black/10">
            <Shield className="w-8 h-8 text-white dark:text-black" />
          </div>
          <h1 className="font-display text-3xl font-bold mb-2">RentShield</h1>
          <p className="text-gray-500 text-sm font-medium">
            {mode === 'setup' ? "Set your Secure PIN" : mode === 'confirm' ? "Confirm your PIN" : "Secure Tenant Access"}
          </p>
        </div>

        <div className="flex justify-center gap-6 mb-16">
          {[0, 1, 2, 3].map(i => (
            <motion.div
              key={i}
              animate={error ? { x: [-5, 5, -5, 5, 0] } : {}}
              className={`w-3.5 h-3.5 rounded-full border-2 border-gray-200 dark:border-gray-800 transition-all ${
                pin.length > i ? 'bg-black dark:bg-white border-black dark:border-white' : 'bg-transparent'
              } ${error ? 'bg-neone-red border-neone-red' : ''}`}
            />
          ))}
        </div>

        <div className="grid grid-cols-3 gap-y-6 gap-x-12 px-6">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(n => (
            <button
              key={n}
              onClick={() => handleNum(n.toString())}
              className="h-14 w-14 mx-auto rounded-full text-xl font-bold font-display hover:bg-gray-100 dark:hover:bg-gray-900 active:scale-90 transition-all"
            >
              {n}
            </button>
          ))}
          <div className="flex items-center justify-center">
             <button onClick={handleBiometric} className="w-12 h-12 flex items-center justify-center rounded-full hover:bg-gray-100 dark:hover:bg-gray-900 transition-all">
                {isAuthenticating ? <Loader2 className="w-6 h-6 animate-spin" /> : <Fingerprint className="w-6 h-6 text-neone-blue" />}
             </button>
          </div>
          <button onClick={() => handleNum('0')} className="h-14 w-14 mx-auto rounded-full text-xl font-bold font-display hover:bg-gray-100 dark:hover:bg-gray-900 active:scale-90 transition-all">0</button>
          <div className="flex items-center justify-center">
            {pin.length > 0 && (
              <button onClick={() => setPin(pin.slice(0, -1))} className="w-12 h-12 flex items-center justify-center text-gray-400 hover:text-black transition-all">
                <ChevronLeft className="w-6 h-6" />
              </button>
            )}
          </div>
        </div>
      </motion.div>
    </div>
  )
}

// --- Pulse (Scanner) View ---

const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [view, setView] = useState<'scan' | 'history'>('scan');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;
    const messages = {
      contract: ["Analyzing clauses...", "Checking 2026 Act...", "Identifying Legal Hazards..."],
      bidding: ["Checking patterns...", "Compiling evidence..."],
      epc: ["Scanning thermal metrics...", "Checking mandates..."]
    };
    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;
    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1500);
    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      try {
        if (mode === 'contract') res = await analyzeContract(base64);
        else if (mode === 'bidding') res = await detectBiddingWar(base64);
        else res = await analyzeEPC(base64);
      } catch (e) {
        res = { isSafe: false, score: 0, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);

      onSaveHistory({
        id: Date.now().toString(),
        date: Date.now(),
        type: mode,
        summary: res.summary || res.evidence || "Scan completed",
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk'
      });
    };
    reader.readAsDataURL(file);
  };

  const simulateIllegalContract = () => {
    setScanning(true);
    setTimeout(() => {
      const res = {
        isSafe: false,
        score: 34,
        summary: "This contract contains several severe legal hazards that violate the Renters' Rights Act 2026.",
        issues: [
          "Illegal Section 21 'No-Fault' Eviction Clause found on Page 4.",
          "Illegal 'Fixed-Term' requirement.",
          "Prohibited 'Professional Cleaning' fee listed.",
          "Unfair 'Pets Prohibited' clause."
        ]
      };
      setResult(res);
      setScanning(false);
      onSaveHistory({ id: Date.now().toString(), date: Date.now(), type: 'contract', summary: res.summary, status: 'risk' });
    }, 3000);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h2 className="font-display text-2xl font-bold">Contract & Rights Check</h2>
        <button 
          onClick={() => setView(view === 'scan' ? 'history' : 'scan')} 
          className="p-2 bg-gray-100 dark:bg-gray-800 rounded-full text-gray-500"
        >
           {view === 'scan' ? <History size={20} /> : <Scan size={20} />}
        </button>
      </div>

      {view === 'history' ? (
        <div className="space-y-4">
           {history.length === 0 ? (
             <p className="text-center py-12 text-gray-500">No scan history yet.</p>
           ) : history.map(item => (
             <SoftCard key={item.id} className="p-4">
                <div className="flex justify-between items-start mb-2">
                   <div className="flex items-center gap-2">
                      <div className="p-1.5 bg-gray-50 dark:bg-gray-800 rounded-lg"><FileText size={16} /></div>
                      <span className="text-xs font-bold uppercase text-gray-400">{item.type}</span>
                   </div>
                   <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${item.status === 'safe' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                    {item.status.toUpperCase()}
                   </span>
                </div>
                <p className="text-xs text-gray-600 dark:text-gray-300 line-clamp-2">{item.summary}</p>
                <div className="mt-2 text-[10px] text-gray-400">{format(item.date, 'dd MMM, HH:mm')}</div>
             </SoftCard>
           ))}
        </div>
      ) : (
        <>
          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-900 rounded-xl">
            {['contract', 'bidding', 'epc'].map((m) => (
              <button
                key={m}
                onClick={() => { setMode(m as any); setResult(null); }}
                className={`flex-1 py-2 text-[11px] font-bold rounded-lg capitalize transition-all ${mode === m ? 'bg-white dark:bg-gray-800 shadow-sm text-black dark:text-white' : 'text-gray-400'}`}
              >
                {m === 'epc' ? 'EPC Check' : m}
              </button>
            ))}
          </div>

          <div className="min-h-[300px] flex flex-col items-center justify-center border-2 border-dashed border-gray-200 dark:border-gray-800 rounded-3xl p-8 bg-gray-50/50 dark:bg-gray-900/50">
            {scanning ? (
              <div className="text-center">
                <div className="relative mb-6">
                  <Scan className="w-16 h-16 text-neone-blue animate-pulse mx-auto" />
                  <motion.div className="absolute top-0 left-0 w-full h-1 bg-neone-blue" animate={{ y: [0, 64, 0] }} transition={{ duration: 2, repeat: Infinity }} />
                </div>
                <p className="text-sm font-bold text-neone-blue animate-pulse uppercase tracking-wider">{loadingMessage}</p>
              </div>
            ) : result ? (
              <div className="w-full text-center">
                 <div className={`w-20 h-20 rounded-full mx-auto mb-6 flex items-center justify-center text-2xl font-bold ${result.isSafe || result.compliance ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                    {result.score || '!'}
                 </div>
                 <h3 className="text-xl font-display font-bold mb-4">{result.isSafe ? 'No Major Risks' : 'Legal Risks Detected'}</h3>
                 <p className="text-sm text-gray-500 mb-6">{result.summary}</p>
                 <NeuButton variant="secondary" className="w-full" onClick={() => setResult(null)}>New Scan</NeuButton>
              </div>
            ) : (
              <div className="text-center">
                <Camera className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                <p className="text-sm text-gray-500 mb-8">Scan your documents or thermal images</p>
                <div className="flex flex-col gap-3">
                   <NeuButton onClick={() => fileInputRef.current?.click()}>
                     <Upload size={18} className="mr-2" /> Upload Document
                   </NeuButton>
                   {mode === 'contract' && (
                     <button onClick={simulateIllegalContract} className="text-[10px] font-bold text-gray-400 hover:text-neone-red transition-colors">
                       SIMULATE ILLEGAL CLAUSE DETECTION
                     </button>
                   )}
                </div>
                <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileUpload} />
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
};

