}

export const NeuButton: React.FC<ButtonProps> = ({ children, variant = 'primary', isLoading, className, ...props }) => {
  const baseStyle = "relative inline-flex items-center justify-center px-6 py-3 font-display font-bold text-base transition-all active:scale-95 disabled:opacity-50 disabled:pointer-events-none rounded-xl";

  const variants = {
    primary: "bg-black text-white dark:bg-white dark:text-black shadow-lg shadow-black/10 hover:bg-gray-800 dark:hover:bg-gray-100",
    secondary: "bg-white dark:bg-gray-800 text-black dark:text-white border border-gray-200 dark:border-gray-700 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-700",
