const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [view, setView] = useState<'scan' | 'history'>('scan');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [loadingMessage, setLoadingMessage] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!scanning) return;
    const messages = {
      contract: ["Analyzing clauses...", "Checking 2026 Act...", "Identifying Legal Hazards..."],
      bidding: ["Checking patterns...", "Compiling evidence..."],
      epc: ["Scanning thermal metrics...", "Checking mandates..."]
    };
    const currentMessages = messages[mode];
    setLoadingMessage(currentMessages[0]);
    let i = 0;
    const interval = setInterval(() => {
      i = (i + 1) % currentMessages.length;
      setLoadingMessage(currentMessages[i]);
    }, 1500);
    return () => clearInterval(interval);
  }, [scanning, mode]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setScanning(true);
    setResult(null);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      try {
        if (mode === 'contract') res = await analyzeContract(base64);
        else if (mode === 'bidding') res = await detectBiddingWar(base64);
        else res = await analyzeEPC(base64);
      } catch (e) {
        res = { isSafe: false, score: 0, summary: "Could not process image.", issues: ["Try a clearer photo"] };
      }

      setResult(res);
      setScanning(false);

      onSaveHistory({
        id: Date.now().toString(),
        date: Date.now(),
        type: mode,
        summary: res.summary || res.evidence || "Scan completed",
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk'
      });
    };
    reader.readAsDataURL(file);
  };

  const simulateIllegalContract = () => {
    setScanning(true);
    setTimeout(() => {
      const res = {
        isSafe: false,
        score: 34,
        summary: "We've analyzed your agreement against the 2026 Renters' Rights Act. Several clauses are legally void (they don't count) and could be used to challenge your landlord.",
        issues: [
          "SECTION 21 ATTEMPT: Your landlord has included a 'no-fault' eviction clause. This is strictly illegal in 2026—you cannot be evicted without a valid legal ground.",
          "ILLEGAL FEE: The '£50 Admin Charge' for keys is prohibited. Landlords can only charge for the actual cost of replacement keys.",
          "INVALID FIXED TERM: The 12-month lock-in period is void. All tenancies are now periodic; you can give notice at any time.",
          "RESTRICTIVE PET BAN: The 'No Pets' blanket ban is illegal. You have a right to request a pet, and consent cannot be unreasonably refused."
        ]
      };
      setResult(res);
      setScanning(false);
      onSaveHistory({ id: Date.now().toString(), date: Date.now(), type: 'contract', summary: res.summary, status: 'risk' });
    }, 2500);
  };

  const handleDownloadReport = () => {
    if (!result) return;
    const reportTitle = "RENTSHIELD 2026 - TENANT PROTECTION REPORT";
    const date = format(new Date(), 'dd MMMM yyyy HH:mm');
    const content = `${reportTitle}\n==========================================\nGenerated: ${date}\nStatus: ${result.isSafe ? 'LEGALLY COMPLIANT' : 'LEGAL RISK DETECTED'}\nProtection Score: ${result.score}/100\n\nEXPLANATION (Plain English):\n${result.summary}\n\nSPECIFIC ILLEGAL CLAUSES FOUND:\n${result.issues?.map((i: string) => `[!] ${i}`).join('\n\n') || 'None - Your contract looks sound.'}\n\n==========================================\nIMPORTANT: This report is for information based on the 2026 Renters' Rights Act. Always consult the Housing Ombudsman or a legal professional for formal disputes.`;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `RentShield_Legal_Report_${format(new Date(), 'yyyy-MM-dd')}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h2 className="font-display text-2xl font-bold">Contract & Rights Check</h2>
        <button 
          onClick={() => setView(view === 'scan' ? 'history' : 'scan')} 
          className="p-2 bg-gray-100 dark:bg-gray-800 rounded-full text-gray-500"
        >
           {view === 'scan' ? <History size={20} /> : <Scan size={20} />}
        </button>
      </div>

      {view === 'history' ? (
        <div className="space-y-4">
           {history.length === 0 ? (
             <p className="text-center py-12 text-gray-500">No scan history yet.</p>
           ) : history.map(item => (
             <SoftCard key={item.id} className="p-4">
                <div className="flex justify-between items-start mb-2">
                   <div className="flex items-center gap-2">
                      <div className="p-1.5 bg-gray-50 dark:bg-gray-800 rounded-lg"><FileText size={16} /></div>
                      <span className="text-xs font-bold uppercase text-gray-400">{item.type}</span>
                   </div>
                   <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${item.status === 'safe' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                    {item.status.toUpperCase()}
                   </span>
                </div>
                <p className="text-xs text-gray-600 dark:text-gray-300 line-clamp-2">{item.summary}</p>
                <div className="mt-2 text-[10px] text-gray-400">{format(item.date, 'dd MMM, HH:mm')}</div>
             </SoftCard>
           ))}
        </div>
      ) : (
        <>
          <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-900 rounded-xl">
            {['contract', 'bidding', 'epc'].map((m) => (
