const TrackerView = () => {
  const [hazards, setHazards] = useState<Hazard[]>([
    {
      id: '1',
      type: 'Black Mould',
      description: 'Damp on living room wall. Landlord has been notified.',
      severity: 'High',
      dateReported: Date.now() - 1000 * 60 * 60 * 24 * 5,
      status: 'Landlord Notified'
    }
  ]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAddHazard = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const analysis = await analyzeHazard(base64);
      setHazards([{
        id: Math.random().toString(36).substr(2, 9),
        type: analysis.type,
        description: analysis.description,
        severity: analysis.severity,
        dateReported: Date.now(),
        status: 'Reported'
      }, ...hazards]);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h2 className="font-display text-2xl font-bold">Housing Problems</h2>
        <NeuButton className="h-10 px-4 text-xs" onClick={() => fileInputRef.current?.click()}>+ Log New</NeuButton>
        <input ref={fileInputRef} type="file" className="hidden" onChange={handleAddHazard} />
      </div>

      <div className="space-y-4">
        {hazards.map(h => {
          const daysElapsed = differenceInDays(Date.now(), h.dateReported);
          const daysLeft = Math.max(0, 14 - daysElapsed);
          const progress = Math.min(100, (daysElapsed / 14) * 100);

          return (
            <SoftCard key={h.id}>
              <div className="flex justify-between items-start mb-3">
                 <div>
                    <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-full ${h.severity === 'High' ? 'bg-red-50 text-red-600' : 'bg-amber-50 text-amber-600'}`}>
                      {h.severity} Severity
                    </span>
                    <h3 className="text-lg font-display font-bold mt-1">{h.type}</h3>
                 </div>
                 <div className="text-right">
                    <p className="text-[10px] font-bold text-gray-400 uppercase">Action Window</p>
                    <p className="text-sm font-bold text-neone-red">{daysLeft} days left</p>
                 </div>
              </div>

              <div className="w-full h-1.5 bg-gray-100 dark:bg-gray-800 rounded-full mb-4 overflow-hidden">
                <motion.div className="h-full bg-neone-red" initial={{ width: 0 }} animate={{ width: `${progress}%` }} />
              </div>

              <p className="text-xs text-gray-500 mb-4">{h.description}</p>

              <div className="flex gap-2">
                 <NeuButton variant="secondary" className="flex-1 py-2 text-xs">Update Status</NeuButton>
                 {daysLeft === 0 && <NeuButton variant="danger" className="flex-1 py-2 text-xs">Notify Ombudsman</NeuButton>}
              </div>
            </SoftCard>
          );
        })}
      </div>
    </div>
  );
};

