const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const res = await analyzeContract(base64);
      setResult(res);
      setScanning(false);
      onSaveHistory({ id: Date.now().toString(), date: Date.now(), type: 'contract', summary: res.summary, status: res.isSafe ? 'safe' : 'risk' });
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <h2 className="font-display text-2xl font-bold">Scanner</h2>
      <div className="min-h-[300px] flex flex-col items-center justify-center border-2 border-dashed border-gray-200 dark:border-gray-800 rounded-3xl p-8 bg-gray-50/50 dark:bg-gray-900/50">
        {scanning ? <Loader2 className="animate-spin w-8 h-8 text-neone-blue" /> : result ? (
          <div className="w-full">
            <h3 className="font-bold mb-4">{result.isSafe ? 'Secure Document' : 'Legal Risk Detected'}</h3>
            <p className="text-sm bg-white dark:bg-gray-800 p-4 rounded-xl mb-4">{result.summary}</p>
            <NeuButton className="w-full" onClick={() => setResult(null)}>Scan New</NeuButton>
          </div>
        ) : (
          <div className="text-center">
            <Camera className="w-12 h-12 text-gray-300 mx-auto mb-4" />
            <NeuButton onClick={() => fileInputRef.current?.click()}>Upload Document</NeuButton>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleFileUpload} />
          </div>
        )}
      </div>
    </div>
  );
};

