// --- Scanner View ---

const ScannerView = ({ onSaveHistory }: { onSaveHistory: (item: ScanHistoryItem) => void }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleScan = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setScanning(true);
    setResult(null);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      if (mode === 'contract') res = await analyzeContract(base64);
      else if (mode === 'bidding') res = await detectBiddingWar(base64);
      else res = await analyzeEPC(base64);

      setResult(res);
      setScanning(false);
      onSaveHistory({ 
        id: Date.now().toString(), 
        date: Date.now(), 
        type: mode, 
        summary: res.summary || res.evidence, 
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk' 
      });
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <h2 className="text-2xl font-display font-bold">AI Scanner</h2>
      <div className="flex gap-2 p-1 bg-gray-100 dark:bg-gray-900 rounded-xl overflow-x-auto">
        {(['contract', 'bidding', 'epc'] as const).map(m => (
          <button key={m} onClick={() => setMode(m)} className={`px-4 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all ${mode === m ? 'bg-white dark:bg-gray-800 shadow-sm text-black dark:text-white' : 'text-gray-400'}`}>
            {m === 'contract' ? 'Agreement' : m === 'bidding' ? 'Bidding War' : 'EPC Shield'}
          </button>
        ))}
      </div>

      <div className="min-h-[400px] flex flex-col items-center justify-center border-2 border-dashed border-gray-200 dark:border-gray-800 rounded-3xl p-8 bg-gray-50/50 dark:bg-gray-900/50 relative overflow-hidden">
        {scanning ? (
          <div className="text-center">
            <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 2, ease: "linear" }} className="mb-4">
              <Scan className="w-16 h-16 text-neone-blue" />
            </motion.div>
            <p className="text-sm font-bold animate-pulse">Scanning for 2026 Violations...</p>
          </div>
        ) : result ? (
          <div className="w-full space-y-4">
            <div className={`p-4 rounded-2xl flex items-center gap-3 ${ (result.isSafe || !result.isIllegal || result.compliance) ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-700'}`}>
              {(result.isSafe || !result.isIllegal || result.compliance) ? <CheckCircle /> : <AlertCircle />}
              <h3 className="font-bold">Scan Complete: {(result.isSafe || !result.isIllegal || result.compliance) ? 'Compliant' : 'Risk Found'}</h3>
            </div>
            <p className="text-sm bg-white dark:bg-gray-800 p-4 rounded-xl border border-gray-100 dark:border-gray-800">{result.summary || result.evidence}</p>
            {result.issues?.map((issue: string, i: number) => (
              <div key={i} className="text-[11px] p-3 bg-red-100/30 text-red-800 rounded-lg flex gap-2">
                <XCircle size={14} className="flex-shrink-0 mt-0.5" /> {issue}
              </div>
            ))}
            <NeuButton className="w-full" onClick={() => setResult(null)}>Scan New Document</NeuButton>
          </div>
        ) : (
          <div className="text-center">
            <div className="w-20 h-20 bg-white dark:bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-6 shadow-xl">
              <Camera size={32} className="text-gray-300" />
            </div>
            <p className="text-sm text-gray-500 mb-8">Upload a photo of your contract, email, or energy certificate.</p>
            <NeuButton onClick={() => fileInputRef.current?.click()}><Upload className="mr-2" size={18} /> Upload Image</NeuButton>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleScan} />
          </div>
        )}
      </div>
    </div>
  );
};

