const TrackerView = ({ hazards, onAddHazard }: { hazards: Hazard[], onAddHazard: (h: Hazard) => void }) => {
  const [logging, setLogging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleLog = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setLogging(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const res = await analyzeHazard(base64);
      const newHazard: Hazard = {
        id: Date.now().toString(),
        type: res.type,
        description: res.description,
        severity: res.severity as any,
        dateReported: Date.now(),
        status: 'Reported'
      };
      onAddHazard(newHazard);
      setLogging(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
