            )}
          </div>
        ) : (
          <div className="space-y-4">
            <h3 className="font-bold text-sm flex items-center gap-2"><Send size={18} className="text-neone-green" /> Smart Response Generator</h3>
            <textarea value={input} onChange={(e) => setInput(e.target.value)} placeholder="What's the issue? (e.g. Broken window)" className="w-full p-4 text-xs bg-gray-50 dark:bg-gray-800 border-none rounded-xl h-32 focus:ring-2 focus:ring-neone-green" />
            <div className="flex gap-2 overflow-x-auto pb-2">
              {([Tone.DIPLOMATIC, Tone.FIRM, Tone.STRICTLY_LEGAL] as Tone[]).map(t => (
                <button key={t} onClick={() => setTone(t)} className={`px-3 py-1.5 rounded-full text-[10px] font-bold whitespace-nowrap transition-all ${tone === t ? 'bg-black text-white dark:bg-white dark:text-black' : 'bg-gray-100 dark:bg-gray-900 text-gray-500'}`}>
                  {t}
                </button>
              ))}
            </div>
            <NeuButton className="w-full" onClick={handleAction} isLoading={loading}>Generate Draft</NeuButton>
            {result && typeof result === 'string' && (
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="p-4 bg-gray-50 dark:bg-gray-800 rounded-xl text-xs font-mono whitespace-pre-wrap border border-gray-100 dark:border-gray-700 mt-4 relative">
                {result}
                <button onClick={() => navigator.clipboard.writeText(result)} className="absolute top-2 right-2 p-1.5 bg-white dark:bg-gray-700 rounded-lg shadow-sm"><FileText size={14}/></button>
              </motion.div>
            )}
          </div>
        )}
      </SoftCard>
    </div>
  );
};

// --- Profile View ---

const ProfileView = ({ onLogout, darkMode, toggleDarkMode, accessibility, setAccessibility }: any) => {
  const [section, setSection] = useState<'main' | 'account' | 'privacy' | 'accessibility'>('main');

  const renderMain = () => (
    <div className="space-y-4">
      <div className="flex items-center gap-4 mb-8">
        <div className="w-16 h-16 bg-neone-blue/10 rounded-2xl flex items-center justify-center"><User className="text-neone-blue" /></div>
        <div><h2 className="text-2xl font-display font-bold">Adwait</h2><p className="text-xs text-gray-500">Protection Tier: Pro</p></div>
      </div>
      <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setSection('account')}>
        <div className="flex items-center gap-3"><Mail size={18} className="text-neone-blue" /><span className="text-sm font-bold">Account</span></div>
        <ChevronRight size={18} />
      </SoftCard>
      <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setSection('accessibility')}>
        <div className="flex items-center gap-3"><Accessibility size={18} className="text-neone-yellow" /><span className="text-sm font-bold">Accessibility</span></div>
        <ChevronRight size={18} />
      </SoftCard>
      <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={toggleDarkMode}>
        <div className="flex items-center gap-3">{darkMode ? <Moon size={18} /> : <Sun size={18} />}<span className="text-sm font-bold">Dark Mode</span></div>
        <Toggle checked={darkMode} onChange={toggleDarkMode} />
      </SoftCard>
      <NeuButton variant="ghost" className="w-full text-red-500" onClick={onLogout}><LogOut size={18} className="mr-2" /> Sign Out</NeuButton>
    </div>
  );

  return (
    <div className="pb-24">
      {section === 'main' && renderMain()}
      {section === 'account' && (
        <motion.div initial={{ x: 20 }} animate={{ x: 0 }}>
          <button onClick={() => setSection('main')} className="flex items-center gap-2 text-xs font-bold text-gray-400 mb-6"><ChevronLeft size={16}/> BACK</button>
          <h3 className="text-xl font-display font-bold mb-6">Account</h3>
          <SoftCard className="p-4 mb-4"><p className="text-[10px] text-gray-400 font-bold uppercase">Name</p><p className="font-bold">Adwait</p></SoftCard>
          <SoftCard className="p-4"><p className="text-[10px] text-gray-400 font-bold uppercase">Email</p><p className="font-bold">adwait@rentshield.app</p></SoftCard>
        </motion.div>
      )}
      {section === 'accessibility' && (
        <motion.div initial={{ x: 20 }} animate={{ x: 0 }}>
          <button onClick={() => setSection('main')} className="flex items-center gap-2 text-xs font-bold text-gray-400 mb-6"><ChevronLeft size={16}/> BACK</button>
          <h3 className="text-xl font-display font-bold mb-6">Accessibility</h3>
          <SoftCard className="flex items-center justify-between p-4 mb-3">
            <span className="text-sm font-bold">High Contrast</span>
            <Toggle checked={accessibility.highContrast} onChange={(v) => setAccessibility({...accessibility, highContrast: v})} />
          </SoftCard>
          <SoftCard className="flex items-center justify-between p-4">
            <span className="text-sm font-bold">Large Text</span>
            <Toggle checked={accessibility.largeText} onChange={(v) => setAccessibility({...accessibility, largeText: v})} />
          </SoftCard>
        </motion.div>
      )}
    </div>
  );
};

// --- Main App ---

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.OVERVIEW);
  const [darkMode, setDarkMode] = useState(false);
  const [accessibility, setAccessibility] = useState({ highContrast: false, largeText: false });
  const [hazards, setHazards] = useState<Hazard[]>([]);
  const [history, setHistory] = useState<ScanHistoryItem[]>([]);

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [darkMode]);

  return (
    <div className={`min-h-screen transition-all ${accessibility.highContrast ? 'high-contrast' : ''} ${accessibility.largeText ? 'large-text' : ''}`}>
      {!isAuthenticated ? <LoginView onLogin={() => setIsAuthenticated(true)} /> : (
        <main className="max-w-md mx-auto min-h-screen bg-white dark:bg-black shadow-2xl relative overflow-hidden flex flex-col">
          <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
            <AnimatePresence mode="wait">
              <motion.div key={activeTab} initial={{ opacity: 0, x: 5 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -5 }} transition={{ duration: 0.15 }}>
                {activeTab === AppTab.OVERVIEW && <HomeView location="Hackney, London" setTab={setActiveTab} activeHazards={hazards} />}
                {activeTab === AppTab.SCAN && <ScannerView onSaveHistory={(item) => setHistory([item, ...history])} />}
                {activeTab === AppTab.TRACKER && <TrackerView hazards={hazards} onAddHazard={(h) => { setHazards([h, ...hazards]); setActiveTab(AppTab.OVERVIEW); }} />}
                {activeTab === AppTab.RIGHTS && <RightsView />}
                {activeTab === AppTab.PROFILE && <ProfileView onLogout={() => setIsAuthenticated(false)} darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)} accessibility={accessibility} setAccessibility={setAccessibility} />}
              </motion.div>
            </AnimatePresence>
          </div>
          <div className="absolute bottom-0 left-0 w-full bg-white/90 dark:bg-black/90 backdrop-blur-xl border-t border-gray-100 dark:border-gray-800 z-50 h-20 flex justify-around items-center">
            <button onClick={() => setActiveTab(AppTab.OVERVIEW)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.OVERVIEW ? 'text-black dark:text-white' : 'text-gray-400'}`}><HomeIcon size={20} /><span className="text-[10px] font-bold">Home</span></button>
            <button onClick={() => setActiveTab(AppTab.SCAN)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.SCAN ? 'text-black dark:text-white' : 'text-gray-400'}`}><Scan size={20} /><span className="text-[10px] font-bold">Scan</span></button>
            <button onClick={() => setActiveTab(AppTab.TRACKER)} className={`relative -top-6 w-14 h-14 rounded-full bg-neone-red text-white flex items-center justify-center shadow-lg shadow-neone-red/30 transition-transform active:scale-95`}><AlertTriangle size={24} /></button>
            <button onClick={() => setActiveTab(AppTab.RIGHTS)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.RIGHTS ? 'text-black dark:text-white' : 'text-gray-400'}`}><FileText size={20} /><span className="text-[10px] font-bold">Rights</span></button>
            <button onClick={() => setActiveTab(AppTab.PROFILE)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.PROFILE ? 'text-black dark:text-white' : 'text-gray-400'}`}><User size={20} /><span className="text-[10px] font-bold">Profile</span></button>
          </div>
        </main>
      )}
    </div>
  );
}

