import React, { useState, useEffect, useRef } from 'react';
import { Shield, Scan, AlertTriangle, FileText, MapPin, Camera, Upload, CheckCircle, XCircle, Siren, Send, Clock, Home as HomeIcon, Loader2, Fingerprint, ChevronLeft, Lock, Thermometer, ExternalLink, Calculator, User, Settings, LogOut, Bell, Info, RefreshCw, Moon, Sun, Star, History, ThumbsUp, TrendingUp, MessageSquare, ArrowRight, Link as LinkIcon, Calendar, Trash2, Save, Eye, EyeOff, Smartphone, Ghost, Activity, FileLock, ChevronRight, AlertCircle, Sparkles, Download, FileCheck, Accessibility, HelpCircle, MessageSquareQuote } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { analyzeContract, analyzeHazard, detectBiddingWar, generateResponse, analyzeEPC, analyzeRentIncrease, translateLandlordSpeak } from './services/geminiService';
import { NeuButton, SoftCard, NeuAlert, TooltipIcon } from './components/ui';
import { AppTab, Hazard, Tone, ScanHistoryItem } from './types';
import { format, addDays, differenceInDays } from 'date-fns';

// --- Shared Components ---

const Toggle = ({ checked, onChange }: { checked: boolean; onChange: (v: boolean) => void }) => (
  <button 
    onClick={(e) => { e.stopPropagation(); onChange(!checked); }}
    className={`w-11 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${checked ? 'bg-emerald-500' : 'bg-gray-200 dark:bg-gray-700'}`}
  >
    <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${checked ? 'translate-x-5' : 'translate-x-0'}`} />
  </button>
);

const AnimatedLogo = () => (
  <motion.div 
    className="flex items-center gap-2 cursor-pointer group"
    whileHover={{ scale: 1.02 }}
  >
    <div className="w-9 h-9 bg-black dark:bg-white rounded-xl flex items-center justify-center">
      <Shield className="w-5 h-5 text-white dark:text-black" />
    </div>
    <h1 className="font-display text-xl font-bold text-black dark:text-white tracking-tight">
      Rent<span className="text-neone-blue">Shield</span>
    </h1>
  </motion.div>
);

// --- Login & Onboarding Views ---

const LoginView = ({ onLogin }: { onLogin: () => void }) => {
  return (
    <div className="min-h-screen bg-white dark:bg-black flex flex-col items-center justify-center p-8 text-center">
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="max-w-xs w-full space-y-8"
      >
        <div className="flex flex-col items-center gap-4">
          <div className="w-20 h-20 bg-black dark:bg-white rounded-[2.5rem] flex items-center justify-center shadow-2xl">
            <Shield size={40} className="text-white dark:text-black" />
          </div>
          <h1 className="text-4xl font-display font-bold tracking-tight">Rent<span className="text-neone-blue">Shield</span></h1>
          <p className="text-gray-500 font-medium">Protecting Adwait since 2026</p>
        </div>
        <NeuButton className="w-full py-4 text-lg" onClick={onLogin}>Access My Rights</NeuButton>
        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Biometric Security Active</p>
      </motion.div>
    </div>
  );
};

// --- Home View ---

const HomeView = ({ location, setTab, hazards }: { location: string, setTab: (t: AppTab) => void, hazards: Hazard[] }) => (
  <div className="space-y-6 pb-24">
    <header className="flex justify-between items-center">
      <AnimatedLogo />
      <div className="flex flex-col items-end">
         <div className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1">Current Area</div>
         <div className="flex items-center gap-1.5 bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-800 px-3 py-1.5 rounded-full text-xs font-bold text-black dark:text-white shadow-sm">
           <MapPin size={12} className="text-neone-blue" />
           {location}
         </div>
      </div>
    </header>

    <NeuAlert type="success" title="You are Protected">
      Welcome back, Adwait. Section 21 evictions are illegal. Your rights in {location.split(',')[0]} are fully enforced.
    </NeuAlert>

    {hazards.length > 0 && (
      <div className="space-y-3">
        <h3 className="text-xs font-bold uppercase text-gray-400 tracking-wider">Legal Deadlines</h3>
        {hazards.map(h => {
          const daysElapsed = differenceInDays(new Date(), new Date(h.dateReported));
          const daysLeft = Math.max(0, 14 - daysElapsed);
          return (
            <SoftCard key={h.id} className="border-l-4 border-neone-red">
               <div className="flex justify-between items-center">
                  <div>
                    <p className="font-bold text-sm">{h.type}</p>
                    <p className="text-[10px] text-gray-500">Timer started {format(h.dateReported, 'MMM dd')}</p>
                  </div>
                  <div className="text-right">
                    <p className={`text-xl font-display font-bold ${daysLeft <= 3 ? 'text-neone-red' : 'text-neone-yellow'}`}>
                      {daysLeft}d
                    </p>
                    <p className="text-[10px] font-bold text-gray-400">Left</p>
                  </div>
               </div>
            </SoftCard>
          );
        })}
      </div>
    )}

    <div className="grid grid-cols-2 gap-4">
      <SoftCard onClick={() => setTab(AppTab.SCAN)} className="p-4 cursor-pointer hover:border-neone-blue transition-all group h-40 flex flex-col justify-between">
        <Scan size={32} className="text-neone-blue group-hover:scale-110 transition-transform" />
        <div>
          <p className="font-bold">AI Scanner</p>
          <p className="text-[10px] text-gray-500">Contract & Bidding</p>
        </div>
      </SoftCard>
      <SoftCard onClick={() => setTab(AppTab.TRACKER)} className="p-4 cursor-pointer hover:border-neone-red transition-all group h-40 flex flex-col justify-between">
        <AlertTriangle size={32} className="text-neone-red group-hover:scale-110 transition-transform" />
        <div>
          <p className="font-bold">Hazard Log</p>
          <p className="text-[10px] text-gray-500">Awaab's Law</p>
        </div>
      </SoftCard>
    </div>

    <SoftCard className="p-4 bg-gray-50 dark:bg-gray-800/50 border-none">
       <div className="flex justify-between items-center">
          <h4 className="text-xs font-bold">Hackney Council Page</h4>
          <a href="https://hackney.gov.uk/private-tenants" target="_blank" className="p-2 bg-white dark:bg-gray-700 rounded-lg shadow-sm">
            <ExternalLink size={14} className="text-neone-blue" />
          </a>
       </div>
    </SoftCard>
  </div>
);

// --- Core 1: Pulse (Scanner) ---

const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setScanning(true);
    setResult(null);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      if (mode === 'contract') res = await analyzeContract(base64);
      else if (mode === 'bidding') res = await detectBiddingWar(base64);
      else res = await analyzeEPC(base64);

      setResult(res);
      setScanning(false);
      onSaveHistory({ 
        id: Date.now().toString(), 
        date: Date.now(), 
        type: mode, 
        summary: res.summary || res.evidence || "Analysis complete", 
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk' 
      });
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <h2 className="text-2xl font-display font-bold">Compliance Pulse</h2>
      <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-900 rounded-xl overflow-x-auto no-scrollbar">
        {(['contract', 'bidding', 'epc'] as const).map(m => (
          <button key={m} onClick={() => setMode(m)} className={`flex-1 min-w-[100px] py-2 text-[10px] font-bold rounded-lg uppercase tracking-wider transition-all ${mode === m ? 'bg-white dark:bg-gray-800 shadow-sm text-black dark:text-white' : 'text-gray-400'}`}>
            {m === 'epc' ? 'EPC Shield' : m}
          </button>
        ))}
      </div>

      <div className="min-h-[400px] flex flex-col items-center justify-center border-2 border-dashed border-gray-200 dark:border-gray-800 rounded-3xl p-8 bg-gray-50/50 dark:bg-gray-900/50">
        {scanning ? (
          <div className="text-center">
            <Loader2 className="w-12 h-12 text-neone-blue animate-spin mx-auto mb-4" />
            <p className="text-sm font-bold animate-pulse">Scanning for 2026 Act Violations...</p>
          </div>
        ) : result ? (
          <div className="w-full space-y-4">
             <div className={`p-4 rounded-xl flex items-center gap-3 ${ (result.isSafe || !result.isIllegal || result.compliance) ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-700'}`}>
                { (result.isSafe || !result.isIllegal || result.compliance) ? <CheckCircle /> : <AlertCircle />}
                <h3 className="font-bold">Shield Status: {(result.isSafe || !result.isIllegal || result.compliance) ? 'Green' : 'Red'}</h3>
             </div>
             <p className="text-sm bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-50 dark:border-gray-800">{result.summary || result.evidence}</p>
             <NeuButton className="w-full" onClick={() => setResult(null)}>Scan New Document</NeuButton>
          </div>
        ) : (
          <div className="text-center">
            <Camera size={48} className="text-gray-300 mx-auto mb-4" />
            <p className="text-sm text-gray-400 mb-8 max-w-[200px] mx-auto">Upload a clear photo of your contract or message evidence.</p>
            <NeuButton onClick={() => fileInputRef.current?.click()}><Upload className="mr-2" size={18} /> Upload Image</NeuButton>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleUpload} />
          </div>
        )}
      </div>
    </div>
  );
};

// --- Core 2: Hazard Tracker ---

const TrackerView = ({ hazards, onAdd }: { hazards: Hazard[], onAdd: (h: Hazard) => void }) => {
  const [analyzing, setAnalyzing] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleCapture = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setAnalyzing(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const res = await analyzeHazard(base64);
      onAdd({
        id: Date.now().toString(),
        type: res.type,
        description: res.description,
        severity: res.severity as any,
        dateReported: Date.now(),
        status: 'Reported'
      });
      setAnalyzing(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-display font-bold">Hazard Tracker</h2>
        <NeuButton variant="danger" className="h-10 px-4 text-xs" onClick={() => fileRef.current?.click()}>+ Log Hazard</NeuButton>
        <input ref={fileRef} type="file" className="hidden" onChange={handleCapture} />
      </div>

      <NeuAlert type="info" title="Awaab's Law">
        You've reported a hazard. Your landlord now has a 14-day legal window to complete repairs.
      </NeuAlert>

      {analyzing && (
        <SoftCard className="flex items-center gap-4 py-12 justify-center">
           <Loader2 className="animate-spin text-neone-red" />
           <p className="text-sm font-bold">AI Analyzing Severity...</p>
        </SoftCard>
      )}

      <div className="space-y-4">
        {hazards.length === 0 ? (
          <p className="text-center py-12 text-gray-500">No active hazards logged.</p>
        ) : hazards.map(h => (
          <SoftCard key={h.id}>
             <div className="flex justify-between items-start mb-2">
                <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${h.severity === 'Critical' ? 'bg-red-500 text-white' : 'bg-neone-yellow text-black'}`}>{h.severity}</span>
                <span className="text-[10px] font-bold text-gray-400 uppercase">{format(h.dateReported, 'dd MMM')}</span>
             </div>
             <h3 className="font-bold text-lg mb-1">{h.type}</h3>
             <p className="text-xs text-gray-500 mb-4">{h.description}</p>
             <div className="flex items-center gap-2 mb-4">
                <div className="flex-1 h-1.5 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
                   <motion.div initial={{ width: 0 }} animate={{ width: '40%' }} className="h-full bg-neone-red" />
                </div>
                <span className="text-[10px] font-bold text-gray-400">Day 1 of 14</span>
             </div>
             <NeuButton variant="secondary" className="w-full py-2 text-xs">View Evidence Log</NeuButton>
          </SoftCard>
        ))}
      </div>
    </div>
  );
};

// --- Core 4: Smart Response Generator + Rights ---

const RightsView = () => {
  const [activeTool, setActiveTool] = useState<'translator' | 'response'>('translator');
  const [input, setInput] = useState('');
  const [tone, setTone] = useState<Tone>(Tone.DIPLOMATIC);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<any>(null);

  const handleRun = async () => {
    if (!input) return;
    setLoading(true);
    if (activeTool === 'translator') {
      const res = await translateLandlordSpeak(input);
      setResult(res);
    } else {
      const res = await generateResponse(tone, input);
      setResult(res);
    }
    setLoading(false);
  };

  return (
    <div className="space-y-6 pb-24">
      <h2 className="text-2xl font-display font-bold">Rights Lab</h2>
      <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-900 rounded-xl">
        <button onClick={() => { setActiveTool('translator'); setResult(null); }} className={`flex-1 py-2 text-[10px] font-bold rounded-lg transition-all ${activeTool === 'translator' ? 'bg-white dark:bg-gray-800 shadow-sm' : 'text-gray-400'}`}>Translator</button>
        <button onClick={() => { setActiveTool('response'); setResult(null); }} className={`flex-1 py-2 text-[10px] font-bold rounded-lg transition-all ${activeTool === 'response' ? 'bg-white dark:bg-gray-800 shadow-sm' : 'text-gray-400'}`}>Response Gen</button>
      </div>

      <SoftCard>
        {activeTool === 'translator' ? (
          <div className="space-y-4">
             <h3 className="font-bold text-sm flex items-center gap-2"><MessageSquareQuote size={18} className="text-neone-blue" /> Landlord Speak Translator</h3>
             <textarea value={input} onChange={(e) => setInput(e.target.value)} placeholder="Paste message..." className="w-full p-4 text-xs bg-gray-50 dark:bg-gray-800 border-none rounded-xl h-32 focus:ring-2 focus:ring-neone-blue" />
             <NeuButton className="w-full" onClick={handleRun} isLoading={loading}>Translate to Plain English</NeuButton>
             {result && (
               <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="mt-4 space-y-3">
