import { GoogleGenAI, Type } from "@google/genai";

export const analyzeContract = async (imageBase64: string): Promise<{ isSafe: boolean; score: number; summary: string; issues: string[] }> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
          {
            text: `You are an expert UK housing lawyer in 2026. The Renters' Rights Act 2026 is in effect.
            Analyze this tenancy agreement image. Determine a 'Tenant Health Score' from 0 to 100.
            Look for illegal Section 21 clauses, invalid fixed terms, or prohibited fees.
            Return JSON: { isSafe: boolean, score: number, summary: string, issues: string[] }`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isSafe: { type: Type.BOOLEAN },
            score: { type: Type.NUMBER },
            summary: { type: Type.STRING },
            issues: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Contract analysis failed:", error);
    return { isSafe: false, score: 0, summary: "Could not analyze. Clearer image needed.", issues: ["Analysis failed"] };
  }
};

