// --- Scanner View ---

const ScannerView = ({ onSaveHistory, history }: { onSaveHistory: (item: ScanHistoryItem) => void, history: ScanHistoryItem[] }) => {
  const [mode, setMode] = useState<'contract' | 'bidding' | 'epc'>('contract');
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setScanning(true);
    setResult(null);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      let res;
      if (mode === 'contract') res = await analyzeContract(base64);
      else if (mode === 'bidding') res = await detectBiddingWar(base64);
      else res = await analyzeEPC(base64);

      setResult(res);
      setScanning(false);
      onSaveHistory({ 
        id: Date.now().toString(), 
        date: Date.now(), 
        type: mode, 
        summary: res.summary || res.evidence || "Analysis complete", 
        status: (res.isSafe || !res.isIllegal || res.compliance) ? 'safe' : 'risk' 
      });
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <h2 className="text-2xl font-display font-bold">Compliance Pulse</h2>
      <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-900 rounded-xl overflow-x-auto no-scrollbar">
        {(['contract', 'bidding', 'epc'] as const).map(m => (
          <button key={m} onClick={() => setMode(m)} className={`flex-1 min-w-[100px] py-2 text-[10px] font-bold rounded-lg uppercase tracking-wider transition-all ${mode === m ? 'bg-white dark:bg-gray-800 shadow-sm text-black dark:text-white' : 'text-gray-400'}`}>
            {m === 'epc' ? 'EPC Shield' : m}
          </button>
        ))}
      </div>

      <div className="min-h-[400px] flex flex-col items-center justify-center border-2 border-dashed border-gray-200 dark:border-gray-800 rounded-3xl p-8 bg-gray-50/50 dark:bg-gray-900/50">
        {scanning ? (
          <div className="text-center">
            <Loader2 className="w-12 h-12 text-neone-blue animate-spin mx-auto mb-4" />
            <p className="text-sm font-bold animate-pulse">Scanning...</p>
          </div>
        ) : result ? (
          <div className="w-full space-y-4">
             <div className={`p-4 rounded-xl flex items-center gap-3 ${ (result.isSafe || !result.isIllegal || result.compliance) ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-700'}`}>
                { (result.isSafe || !result.isIllegal || result.compliance) ? <CheckCircle /> : <AlertCircle />}
                <h3 className="font-bold">{(result.isSafe || !result.isIllegal || result.compliance) ? 'Compliant' : 'Risk Detected'}</h3>
             </div>
             <p className="text-sm bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-50 dark:border-gray-800">{result.summary || result.evidence}</p>
             <NeuButton className="w-full" onClick={() => setResult(null)}>Scan New</NeuButton>
          </div>
        ) : (
          <div className="text-center">
            <Camera size={48} className="text-gray-300 mx-auto mb-4" />
            <p className="text-sm text-gray-400 mb-8 max-w-[200px] mx-auto">Upload a clear photo to analyze your rights.</p>
            <NeuButton onClick={() => fileInputRef.current?.click()}><Upload className="mr-2" size={18} /> Upload Image</NeuButton>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleUpload} />
          </div>
        )}
      </div>
    </div>
  );
};

// --- Tracker View ---

const TrackerView = ({ hazards, onAdd }: { hazards: Hazard[], onAdd: (h: Hazard) => void }) => {
  const [analyzing, setAnalyzing] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleCapture = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setAnalyzing(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64 = (reader.result as string).split(',')[1];
      const res = await analyzeHazard(base64);
      onAdd({
        id: Date.now().toString(),
        type: res.type,
        description: res.description,
        severity: res.severity as any,
        dateReported: Date.now(),
        status: 'Reported'
      });
      setAnalyzing(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-display font-bold">Hazard Tracker</h2>
        <NeuButton variant="danger" className="h-10 px-4 text-xs" onClick={() => fileRef.current?.click()}>+ Log Hazard</NeuButton>
        <input ref={fileRef} type="file" className="hidden" onChange={handleCapture} />
      </div>

      <NeuAlert type="info" title="Awaab's Law Tracking">
        Reported issues trigger a legal 14-day mandatory fix window for landlords.
      </NeuAlert>

      {analyzing && (
        <SoftCard className="flex items-center gap-4 py-12 justify-center">
           <Loader2 className="animate-spin text-neone-red" />
           <p className="text-sm font-bold">AI Analyzing...</p>
        </SoftCard>
      )}

      <div className="space-y-4">
        {hazards.length === 0 ? (
          <p className="text-center py-12 text-gray-500">No active hazards logged.</p>
        ) : hazards.map(h => (
          <SoftCard key={h.id}>
             <div className="flex justify-between items-start mb-2">
                <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${h.severity === 'Critical' ? 'bg-red-500 text-white' : 'bg-neone-yellow text-black'}`}>{h.severity}</span>
                <span className="text-[10px] font-bold text-gray-400 uppercase">{format(h.dateReported, 'dd MMM')}</span>
             </div>
             <h3 className="font-bold text-lg mb-1">{h.type}</h3>
             <p className="text-xs text-gray-500 mb-4">{h.description}</p>
             <div className="flex items-center gap-2 mb-4">
                <div className="flex-1 h-1.5 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
                   <motion.div initial={{ width: 0 }} animate={{ width: '40%' }} className="h-full bg-neone-red" />
                </div>
                <span className="text-[10px] font-bold text-gray-400">Fix Window</span>
             </div>
             <NeuButton variant="secondary" className="w-full py-2 text-xs">View Legal Timeline</NeuButton>
          </SoftCard>
        ))}
      </div>
    </div>
  );
};

