  const [notifications, setNotifications] = useState({ deadlines: true, legal: true, market: false });
  const [hazards, setHazards] = useState<Hazard[]>([]);
  const [history, setHistory] = useState<ScanHistoryItem[]>([]);
  const [locationName, setLocationName] = useState('Locating...');
  const [toast, setToast] = useState<{msg: string, id: number} | null>(null);

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [darkMode]);

  useEffect(() => {
    if (isAuthenticated) {
      // Simulate geolocation for accurate Adwait persona
      const timer = setTimeout(() => {
        setLocationName('Hackney, London');
      }, 1500);
      return () => clearTimeout(timer);
    }
  }, [isAuthenticated]);

  const showToast = (msg: string) => {
    setToast({ msg, id: Date.now() });
    setTimeout(() => setToast(null), 3000);
  };

  return (
    <div className={`min-h-screen transition-all duration-300 ${accessibility.highContrast ? 'high-contrast' : ''} ${accessibility.largeText ? 'large-text' : ''}`}>
      {!isAuthenticated ? <LoginView onLogin={() => setIsAuthenticated(true)} /> : (
        <main className="max-w-md mx-auto min-h-screen bg-white dark:bg-black shadow-2xl relative overflow-hidden flex flex-col">
          <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
            <AnimatePresence mode="wait">
              <motion.div key={activeTab} initial={{ opacity: 0, x: 5 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -5 }} transition={{ duration: 0.15 }}>
                {activeTab === AppTab.OVERVIEW && <HomeView location={locationName} setTab={setActiveTab} hazards={hazards} />}
                {activeTab === AppTab.SCAN && <ScannerView onSaveHistory={(item) => setHistory([item, ...history])} history={history} />}
                {activeTab === AppTab.TRACKER && <TrackerView hazards={hazards} onAdd={(h) => { setHazards([h, ...hazards]); setActiveTab(AppTab.OVERVIEW); }} />}
                {activeTab === AppTab.RIGHTS && <RightsView />}
                {activeTab === AppTab.PROFILE && <ProfileView onLogout={() => setIsAuthenticated(false)} darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)} accessibility={accessibility} setAccessibility={setAccessibility} notifications={notifications} setNotifications={setNotifications} showToast={showToast} />}
              </motion.div>
            </AnimatePresence>
          </div>

          <AnimatePresence>
            {toast && <Toast message={toast.msg} onClose={() => setToast(null)} />}
          </AnimatePresence>

          <div className="absolute bottom-0 left-0 w-full bg-white/90 dark:bg-black/90 backdrop-blur-xl border-t border-gray-100 dark:border-gray-800 z-50 h-20 flex justify-around items-center">
            <button onClick={() => setActiveTab(AppTab.OVERVIEW)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.OVERVIEW ? 'text-black dark:text-white' : 'text-gray-400'}`}><HomeIcon size={20} /><span className="text-[10px] font-bold">Home</span></button>
            <button onClick={() => setActiveTab(AppTab.SCAN)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.SCAN ? 'text-black dark:text-white' : 'text-gray-400'}`}><Scan size={20} /><span className="text-[10px] font-bold">Scanner</span></button>

            <button onClick={() => setActiveTab(AppTab.TRACKER)} className={`relative -top-6 w-14 h-14 rounded-full bg-neone-red text-white flex items-center justify-center shadow-lg shadow-neone-red/30 transition-transform active:scale-95`}>
              <AlertTriangle size={24} />
            </button>

            <button onClick={() => setActiveTab(AppTab.RIGHTS)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.RIGHTS ? 'text-black dark:text-white' : 'text-gray-400'}`}><FileText size={20} /><span className="text-[10px] font-bold">Rights</span></button>
            <button onClick={() => setActiveTab(AppTab.PROFILE)} className={`flex flex-col items-center p-2 ${activeTab === AppTab.PROFILE ? 'text-black dark:text-white' : 'text-gray-400'}`}><User size={20} /><span className="text-[10px] font-bold">Profile</span></button>
          </div>
        </main>
      )}
    </div>
  );
}

import React from 'react';
// Added AnimatePresence to the imports from framer-motion
import { motion, AnimatePresence, HTMLMotionProps } from 'framer-motion';
import { Loader2, Info } from 'lucide-react';

interface ButtonProps extends HTMLMotionProps<"button"> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const NeuButton: React.FC<ButtonProps> = ({ children, variant = 'primary', isLoading, className, ...props }) => {
  const baseStyle = "relative inline-flex items-center justify-center px-6 py-3 font-display font-bold text-base transition-all active:scale-95 disabled:opacity-50 disabled:pointer-events-none rounded-xl";

  const variants = {
    primary: "bg-black text-white dark:bg-white dark:text-black shadow-lg shadow-black/10 hover:bg-gray-800 dark:hover:bg-gray-100",
    secondary: "bg-white dark:bg-gray-800 text-black dark:text-white border border-gray-200 dark:border-gray-700 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-700",
    danger: "bg-neone-red text-white shadow-lg shadow-neone-red/20 hover:brightness-110",
    ghost: "text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800"
  };

  return (
    <motion.button 
      whileTap={{ scale: 0.98 }}
      className={`${baseStyle} ${variants[variant]} ${className || ''}`}
      {...props}
    >
      {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
      {children}
    </motion.button>
  );
};

export const SoftCard: React.FC<{ children: React.ReactNode; className?: string; onClick?: () => void }> = ({ children, className, onClick }) => (
  <motion.div 
    initial={{ opacity: 0, y: 10 }}
    animate={{ opacity: 1, y: 0 }}
    onClick={onClick}
    className={`bg-white dark:bg-gray-900 rounded-2xl p-5 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 dark:border-gray-800 text-black dark:text-white ${className || ''}`}
  >
    {children}
  </motion.div>
);

export const NeuAlert: React.FC<{ type: 'danger' | 'info' | 'success'; title: string; children: React.ReactNode }> = ({ type, title, children }) => {
  const colors = {
    danger: 'bg-red-50 text-red-900 border-red-100 dark:bg-red-900/10 dark:text-red-400 dark:border-red-900/30',
    info: 'bg-blue-50 text-blue-900 border-blue-100 dark:bg-blue-900/10 dark:text-blue-400 dark:border-blue-900/30',
    success: 'bg-emerald-50 text-emerald-900 border-emerald-100 dark:bg-emerald-900/10 dark:text-emerald-400 dark:border-emerald-900/30',
  };

  return (
    <div className={`${colors[type]} border p-4 mb-4 rounded-xl flex gap-3 items-start`}>
      <div className="mt-0.5">
        {type === 'danger' && '⚠️'} 
        {type === 'success' && '🛡️'}
        {type === 'info' && 'ℹ️'}
      </div>
      <div>
        <h4 className="font-display font-bold text-sm mb-1">
          {title}
        </h4>
        <p className="font-sans text-xs opacity-90 leading-relaxed">{children}</p>
      </div>
    </div>
