  const handleNotifyToggle = (key: keyof typeof notifications, val: boolean) => {
    setNotifications({ ...notifications, [key]: val });
    showToast(val ? `${String(key)} alerts enabled` : `${String(key)} alerts disabled`);
  };

  const renderMain = () => (
    <div className="space-y-4">
      <div className="flex items-center gap-4 mb-8">
        <div className="w-16 h-16 bg-neone-blue/10 rounded-2xl flex items-center justify-center">
          <User className="text-neone-blue" size={32} />
        </div>
        <div>
          <h2 className="text-2xl font-display font-bold">Adwait</h2>
          <p className="text-xs text-gray-500">Hackney, London • Tenant Protector</p>
