      </div>

      <div className="space-y-2">
        <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setSection('notifications')}>
          <div className="flex items-center gap-3"><Bell size={18} className="text-neone-blue" /><span className="text-sm font-bold">Notifications</span></div>
          <ChevronRight size={18} />
        </SoftCard>
        <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setSection('privacy')}>
          <div className="flex items-center gap-3"><ShieldCheck size={18} className="text-neone-green" /><span className="text-sm font-bold">Privacy</span></div>
          <ChevronRight size={18} />
        </SoftCard>
        <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setSection('accessibility')}>
          <div className="flex items-center gap-3"><Accessibility size={18} className="text-neone-yellow" /><span className="text-sm font-bold">Accessibility</span></div>
          <ChevronRight size={18} />
        </SoftCard>
        <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setSection('help')}>
          <div className="flex items-center gap-3"><HelpCircle size={18} className="text-purple-500" /><span className="text-sm font-bold">Help & Support</span></div>
          <ChevronRight size={18} />
        </SoftCard>
        <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={() => setSection('feedback')}>
          <div className="flex items-center gap-3"><MessageSquare size={18} className="text-orange-500" /><span className="text-sm font-bold">Feedback</span></div>
          <ChevronRight size={18} />
        </SoftCard>
        <SoftCard className="flex items-center justify-between p-4 cursor-pointer" onClick={toggleDarkMode}>
          <div className="flex items-center gap-3">{darkMode ? <Moon size={18} /> : <Sun size={18} />}<span className="text-sm font-bold">Dark Mode</span></div>
          <Toggle checked={darkMode} onChange={toggleDarkMode} />
        </SoftCard>
        <NeuButton variant="ghost" className="w-full text-red-500 mt-4" onClick={onLogout}><LogOut size={18} className="mr-2" /> Sign Out</NeuButton>
      </div>
    </div>
  );

  return (
    <div className="pb-24">
       <AnimatePresence mode="wait">
          {section === 'main' ? renderMain() : (
            <motion.div initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -20, opacity: 0 }}>
               <button onClick={() => setSection('main')} className="flex items-center gap-2 text-xs font-bold text-gray-400 mb-6"><ChevronLeft size={16} /> BACK</button>
               <h3 className="text-xl font-display font-bold mb-6 capitalize">{section}</h3>

               {section === 'notifications' && (
                  <div className="space-y-3">
                     <SoftCard className="flex items-center justify-between p-4">
                        <div><p className="text-sm font-bold">Hazard Deadlines</p><p className="text-[10px] text-gray-400">Fix window expiration alerts</p></div>
                        <Toggle checked={notifications.deadlines} onChange={(v) => handleNotifyToggle('deadlines', v)} />
                     </SoftCard>
                     <SoftCard className="flex items-center justify-between p-4">
                        <div><p className="text-sm font-bold">Legal Updates</p><p className="text-[10px] text-gray-400">New Renters' Rights news</p></div>
                        <Toggle checked={notifications.legal} onChange={(v) => handleNotifyToggle('legal', v)} />
                     </SoftCard>
                     <SoftCard className="flex items-center justify-between p-4">
                        <div><p className="text-sm font-bold">Market Alerts</p><p className="text-[10px] text-gray-400">Local rent trend warnings</p></div>
                        <Toggle checked={notifications.market} onChange={(v) => handleNotifyToggle('market', v)} />
                     </SoftCard>
                  </div>
               )}

               {section === 'privacy' && (
                  <div className="space-y-3">
                     <SoftCard className="flex items-center justify-between p-4">
